Single.Single:
// ============================================================
// Máquina de estados de escrita em inversores
// ============================================================

// estado default por ciclo
result := E_ModbusResult.BUSY;

tonTimer(IN := (state = WAIT), PT := tTimeout);

CASE state OF

    TRIG:
        trigInv := TRUE;
        state := WAIT;

    WAIT:
    	IF pSlave.xDone THEN
            trigInv := FALSE;
            state := TRIG;
            result := E_ModbusResult.DONE;
		
      	ELSIF pSlave.xError THEN
            fbChannel(Slave := pSlave, iChannelIndex := 0);
            state := TRIG;
            trigInv := FALSE;
            result := E_ModbusResult.ERRO;
			FC_LogEvent(
				eCode:=TO_UINT(pSlave.byModbusError) + 16#4A00,
				bRaised:=TRUE,
				rParam1:=0.0,
				rParam2:=0.0,
				uMachState := GVL_Main.uMachineState
				);
			
      	ELSIF tonTimer.Q THEN
            state := TRIG;
            trigInv := FALSE;
            result := E_ModbusResult.TIMEOUT;
        END_IF
END_CASE

FUNCTION_BLOCK FB_ModBus

VAR_INPUT
    tTimeout    : TIME;
END_VAR

VAR_IN_OUT
    trigInv     : BOOL;                    // ex.: Global.trigInvCOM100[i]
    pSlave      : ModbusSlaveComPort;      // ex.: Global.pInversores100[i]^
END_VAR

VAR_OUTPUT
    result      : E_ModbusResult;
END_VAR

VAR
    fbChannel   : ModbusChannel;
    state       : (TRIG, WAIT) := TRIG;
    tonTimer    : TON;
END_VAR

// INICIA AQUI

auxK1_in := GVL_Main.K1_in;
auxK2_in := GVL_Main.K2_in;

CASE stState OF 																				// Máquina de estados

	E_StartupStatus.stInit:																		// Inicialização única
	   
		cmdK01 			:= FALSE;
		auxRed  		:= FALSE;
		auxYellow 		:= FALSE;
		auxGreen  		:= FALSE;
		debouncedK1 	:= FALSE;
		debouncedK2 	:= FALSE;
		
		// Testa leitura do relógio do sistema na inicialização
		GVL_Main.timestampUTC := TO_UDINT(SysTimeRtcGet(GVL_Main.Result)); 							// UDINT#1528268918
		GVL_ALARM_MANAGER.CRIT_RTC_FAIL:=(GVL_Main.Result <> eResultCode.OK);                        // Em caso de erro de leitura do relógio, vai para STOP
		IF GVL_ALARM_MANAGER.CRIT_RTC_FAIL THEN 														
			GVL_Main.K3RedOut:=TRUE;																// sinalizar que houve erro para ler o relógio
			FC_LogEvent(
				eCode      := E_EventCode.CRIT_RTC_FAILED,
				bRaised    := TRUE,
				rParam1    := 0.0,
				rParam2    := 0.0,
				uMachState := GVL_Main.uMachineState
			);
			RETURN;
		END_IF
		
		// Testa seriais 
		eDeviceState01 := Master_01.GetDeviceState(
			xDiagnosisInfoAvailable => xDiagInfoIsAvailable01,
			eError                  => eError01
			);
		eDeviceState02 := Master_02.GetDeviceState(
			xDiagnosisInfoAvailable => xDiagInfoIsAvailable02,
			eError                  => eError02
			);
  		xMaster01IsReady := (eDeviceState01 = DED.DEVICE_STATE.RUNNING); 
   		xMaster02IsReady := (eDeviceState02 = DED.DEVICE_STATE.RUNNING); 
		
		GVL_ALARM_MANAGER.CRIT_SERIAL_INIT_FAIL:=(xMaster01IsReady AND xMaster02IsReady);		
		
		IF NOT GVL_ALARM_MANAGER.CRIT_SERIAL_INIT_FAIL THEN
			stState := E_StartupStatus.stInit;
		ELSE
			GVL_Main.K3RedOut:=TRUE;
			stState := E_StartupStatus.stError;
			FC_LogEvent(
				eCode      := E_EventCode.CRIT_SERIAL_INIT_FAILED,
				bRaised    := TRUE,
				rParam1    := 0.0,
				rParam2    := 0.0,
				uMachState := GVL_Main.uMachineState
			);
		END_IF
	
		// Porta de comunicação COM1
		GVL_Main.pMedidor100   		:= ADR(Medidor100);
		GVL_Main.pInversores100[1]  := ADR(Inversor101);
		GVL_Main.pInversores100[2]  := ADR(Inversor102);
		GVL_Main.pInversores100[3]	:= ADR(Inversor103);
		GVL_Main.pInversores100[4] 	:= ADR(Inversor104);
		GVL_Main.pInversores100[5]	:= ADR(Inversor105);
		GVL_Main.pInversores100[6] 	:= ADR(Inversor106);
		GVL_Main.pInversores100[7] 	:= ADR(Inversor107);
		GVL_Main.pInversores100[8] 	:= ADR(Inversor108);
		GVL_Main.pInversores100[9] 	:= ADR(Inversor109);
		GVL_Main.pInversores100[10]	:= ADR(Inversor110);
		GVL_Main.pInversores100[11]	:= ADR(Inversor111);
		GVL_Main.pInversores100[12] := ADR(Inversor112);
		GVL_Main.pInversores100[13] := ADR(Inversor113);
		GVL_Main.pInversores100[14] := ADR(Inversor114);
		GVL_Main.pInversores100[15] := ADR(Inversor115);
		
		// Porta de comunicação COM2
		GVL_Main.pMedidor200   	  	:= ADR(Medidor200);
		GVL_Main.pInversores200[1]  := ADR(Inversor201);
		GVL_Main.pInversores200[2]  := ADR(Inversor202);
		GVL_Main.pInversores200[3]  := ADR(Inversor203);
		GVL_Main.pInversores200[4]  := ADR(Inversor204);
		GVL_Main.pInversores200[5] 	:= ADR(Inversor205);
		GVL_Main.pInversores200[6]  := ADR(Inversor206);
		GVL_Main.pInversores200[7]  := ADR(Inversor207);
		GVL_Main.pInversores200[8]  := ADR(Inversor208);
		GVL_Main.pInversores200[9]  := ADR(Inversor209);
		GVL_Main.pInversores200[10] := ADR(Inversor210);
		GVL_Main.pInversores200[11] := ADR(Inversor211);
		GVL_Main.pInversores200[12] := ADR(Inversor212);
		GVL_Main.pInversores200[13] := ADR(Inversor213);
		GVL_Main.pInversores200[14] := ADR(Inversor214);
		GVL_Main.pInversores200[15] := ADR(Inversor215);
		
		FOR indice := 1 TO 15 DO														// inicialização dos canais de comunicação
			fbChannel(Slave := GVL_Main.pInversores100[indice]^,xExecute := FALSE,xAbort := FALSE,iChannelIndex := 0);
			fbChannel(Slave := GVL_Main.pInversores200[indice]^,xExecute := FALSE,xAbort := FALSE,iChannelIndex := 0); 
		END_FOR
	
		// =========================================================================================
		// 0. PREPARAÇÃO DO TEMPO DE CICLO - feito na inicialização
		// =========================================================================================
		// Converte TIME (ex: T#500ms) para REAL (0.5 segundos) para uso nos PIDs
		GVL_Main.ControlCycle := UDINT_TO_REAL(GVL_Main.CYCLE_TIME_MS)/1000;  				// converte para segundos
			
		// ============================================================
		// CONTAGEM AUTOMÁTICA DE INVERSORES (sequencial por potência)
		// ============================================================
		
		// COM1: índices 1..15
		GVL_Main.NInversoresCOM01 := 0;
		FOR indice := 1 TO 15 DO
			IF GVL_Persis.InvActivePower[indice] > 0.0 THEN
				GVL_Main.NInversoresCOM01 := indice;   // mantém maior índice válido
			ELSE
				EXIT;  // encontrou buraco -> encerra contagem
			END_IF
		END_FOR
		
		// COM2: índices 16..30
		GVL_Main.NInversoresCOM02 := 0;
		FOR indice := 16 TO 30 DO
			IF GVL_Persis.InvActivePower[indice] > 0.0 THEN
				GVL_Main.NInversoresCOM02 := indice - 15;   // converte para faixa 1..15
			ELSE
				EXIT;  // encontrou buraco -> encerra contagem
			END_IF
		END_FOR		
		
		GVL_Main.MAX_CH1_MODBUS_ERROS		:= GVL_Main.NInversoresCOM01 / 2;					// permite < 50% da quantidade de inversores sem ir para FAIL
		GVL_Main.MAX_CH1_MODBUS_TIMEOUTS	:= GVL_Main.NInversoresCOM01 / 2;					// permite < 50% da quantidade de inversores sem ir para FAIL
		GVL_Main.MAX_CH2_MODBUS_ERROS		:= GVL_Main.NInversoresCOM02 / 2;					// permite < 50% da quantidade de inversores sem ir para FAIL
		GVL_Main.MAX_CH2_MODBUS_TIMEOUTS	:= GVL_Main.NInversoresCOM02 / 2;					// permite < 50% da quantidade de inversores sem ir para FAIL
		
		// =========================================================================================
		// 1. CÁLCULO DA POTÊNCIA INSTALADA TOTAL (Ativa e Aparente)  - feito na inicialização
		// =========================================================================================
		// Soma a capacidade nominal de todos os inversores configurados.
		// Isso permite mudar a planta dinamicamente sem recompilar.
		
		GVL_Main.InstalledPower := 0.0;
		GVL_Main.InstalledSmax  := 0.0;
		
		FOR indice := 1 TO GVL_Main.NMAXINVERSORES DO
			// Soma Potência Ativa Máxima (kW)
			GVL_Main.InstalledPower := GVL_Main.InstalledPower + GVL_Persis.InvActivePower[indice];
			// Soma Potência Aparente Máxima (kVA)
			GVL_Main.InstalledSmax := GVL_Main.InstalledSmax + GVL_Persis.InvSmaxPower[indice];
		END_FOR

		// Se não houver inversores ou potência válida, zera tudo e sai
		
		GVL_ALARM_MANAGER.CRIT_INSTALLED_PWR_ZERO:= (GVL_Main.InstalledPower <= 0.0);
		IF GVL_ALARM_MANAGER.CRIT_INSTALLED_PWR_ZERO THEN
			GVL_Main.TotalReactivePower := 0.0;
			GVL_Main.K3RedOut:=TRUE;
			stState := E_StartupStatus.stError;
			FC_LogEvent(
				eCode      := E_EventCode.CRIT_NO_INSTALLED_POWER,
				bRaised    := TRUE,
				rParam1    := 0.0,
				rParam2    := 0.0,
				uMachState := GVL_Main.uMachineState
			);
			RETURN;
		END_IF
		
		GVL_ALARM_MANAGER.CRIT_INSTALLED_SMAX_ZERO:= (GVL_Main.InstalledSmax <= 0.0);
		IF GVL_ALARM_MANAGER.CRIT_INSTALLED_SMAX_ZERO THEN
			GVL_Main.TotalReactivePower := 0.0;
			GVL_Main.K3RedOut:=TRUE;
			stState := E_StartupStatus.stError;
			FC_LogEvent(
				eCode      := E_EventCode.CRIT_INSTALLED_SMAX_ZERO,
				bRaised    := TRUE,
				rParam1    := 0.0,
				rParam2    := 0.0,
				uMachState := GVL_Main.uMachineState
			);
			RETURN;
		END_IF
		
		// Calcula Q_max_permitido 
	    GVL_Main.Q_max_permitido := GVL_Main.InstalledPower * 0.4256;  // tan(acos(0.92))
			
		// Configura TC_Power_kW se não foi configurado
		GVL_ALARM_MANAGER.ALARM_TC_POWER_NOT_SET:=(GVL_Persis.TC_Power_kW = 0.0);
		IF GVL_ALARM_MANAGER.ALARM_TC_POWER_NOT_SET THEN
			GVL_Persis.TC_Power_kW := GVL_Main.InstalledPower;  // Aproximação conservadora
			FC_LogEvent(
				eCode      := E_EventCode.WARN_TC_POWER_NOT_SET,
				bRaised    := TRUE,
				rParam1    := 0.0,
				rParam2    := 0.0,
				uMachState := GVL_Main.uMachineState
			);
		END_IF

		// Muda para próximo estado	
		stState := E_StartupStatus.stWait_K1;

	E_StartupStatus.stWait_K1:															// DEBOUNCE K1
        
		cmdK01 := TRUE;
		auxRed := TRUE;																	// Status: aguardando K1 com debounce
		auxYellow := FALSE;
		auxGreen := FALSE;
		
		TonDebounceK1(IN := TRUE, PT := TimeDebounceK1);
		TonK1Timeout (IN := TRUE, PT := TimeK1Timeout);   

		IF TonDebounceK1.Q THEN
		  debouncedK1 := TRUE;
		ELSE
		  debouncedK1 := FALSE;
		END_IF
	
		IF debouncedK1 AND (auxK1_in=TRUE) THEN
		  // Para o timeout (não é mais necessário)
		  TonK1Timeout(IN := FALSE);
		  stState := E_StartupStatus.stWait_K2;												// Somente avança se K1 está estabilizado
		  debouncedK2 := FALSE;
		  TonDebounceK1(IN := FALSE, PT := TimeDebounceK1); 								// (Opcional) reseta timer
		  auxRed := FALSE;																	// Status: aguardando K1 com debounce
		  auxYellow := TRUE;
		  auxGreen := FALSE;
		  FC_LogEvent(
			eCode      := E_EventCode.INFO_K1_CONFIRMED,
			bRaised    := TRUE,
			rParam1    := 0.0,
			rParam2    := 0.0,
			uMachState := GVL_Main.uMachineState
		  );
		END_IF
		
		GVL_ALARM_MANAGER.CRIT_K1_TIMEOUT:=TonK1Timeout.Q;
		
		// Se estourou timeout antes de confirmar debounce, gera alarme + evento crítico (1x)
		IF GVL_ALARM_MANAGER.CRIT_K1_TIMEOUT THEN
			FC_LogEvent(
				eCode      := E_EventCode.CRIT_K1_TIMEOUT,
				bRaised    := TRUE,
				rParam1    := 0.0,
				rParam2    := 0.0,
				uMachState := GVL_Main.uMachineState
			);
		 	TonK1Timeout(IN := FALSE);
			stState := E_StartupStatus.stError;
		END_IF

	E_StartupStatus.stWait_K2:	
  
  		TonDebounceK2(IN := TRUE, PT := TimeDebounceK2);  // debounce para K2_in
		TonK2Timeout (IN := TRUE, PT := TimeK2Timeout);   
		
		IF TonDebounceK2.Q THEN																// tDebounce.Q será TRUE se K2_in estável
		  debouncedK2 := TRUE;
		ELSE     																					
		  debouncedK2 := FALSE;																// se K2_in voltar a false, reseta timer
		END_IF
	
		IF debouncedK2 AND (auxK2_in=TRUE) THEN
		  TonK2Timeout(IN := FALSE);
		  stState := E_StartupStatus.stDone;												// K2_ok e estável, processo de startup completo
		  TonDebounceK2(IN := FALSE, PT := TimeDebounceK2); 								// (Opcional) reseta timer
		  auxRed := FALSE;																	
		  auxYellow := FALSE;
		  auxGreen := TRUE;
		  FC_LogEvent(
			eCode      := E_EventCode.INFO_K2_CONFIRMED,
			bRaised    := TRUE,
			rParam1    := 0.0,
			rParam2    := 0.0,
			uMachState := GVL_Main.uMachineState
		  );
		END_IF

		GVL_ALARM_MANAGER.CRIT_K2_TIMEOUT:=TonK2Timeout.Q;
		
		// Se estourou timeout antes de confirmar debounce, gera alarme + evento crítico (1x)
		IF GVL_ALARM_MANAGER.CRIT_K2_TIMEOUT THEN
			FC_LogEvent(
				eCode      := E_EventCode.CRIT_K2_DID_NOT_OPEN,
				bRaised    := TRUE,
				rParam1    := 0.0,
				rParam2    := 0.0,
				uMachState := GVL_Main.uMachineState
			);
			stState := E_StartupStatus.stError;
		END_IF		
		
	
	E_StartupStatus.stDone:
	
		stState := E_StartupStatus.stDone;
		auxRed := FALSE;		
		auxYellow := FALSE;
		auxGreen := TRUE;
		FC_LogEvent(
			eCode      := E_EventCode.INFO_STARTUP_DONE,
			bRaised    := TRUE,
			rParam1    := 0.0,
			rParam2    := 0.0,
			uMachState := GVL_Main.uMachineState
		);

END_CASE;

//   Aplicar comandos calculados às saídas físicas / públicas
GVL_Main.K1_out 		:= cmdK01;
GVL_Main.K3RedOut 		:= auxRed;
GVL_Main.K4YellowOut 	:= auxYellow;
GVL_Main.K5GreenOut 	:= auxGreen;

(* FB: fbStartup 1) Ativa K1_out 2) Aguarda 400 ms antes de verificar se K1_in está ativo -> Se K1_in NÃO estiver ativo depois deste tempo, sinaliza erro e sai da fbStartup 3) Monitorar K2_in com debounce até ficar ativo 4) Enquanto aguarda K2_in ativar, mantém K4_out ativo 5) Quando K2_in ativar (após debounced), desativa K4_out e ativa K5_out 6) O controlador aguarda até K2_in = TRUE Notas: - IMPORTANTE: se não forem usados contados auxiliares nos disjuntores, K1_in e K2_in precisam ser conectados a 24V - Este FB apenas sinaliza os outputs K1_out, K3_out, K4_out e K5_out. - Implementado com máquina de estados e TONs (tDelay e tDebounce). TON deve ser chamado toda iteração. *)
FUNCTION_BLOCK FB_Startup VAR_OUTPUT stState : E_StartupStatus:= E_StartupStatus.stInit; END_VAR
VAR fbChannel : ModbusChannel; debouncedK1 : BOOL := FALSE; // flag auxiliar informando que K1_in está estável em 1 TonDebounceK1 : TON; // Novo timer debounce K1_in TimeDebounceK1 : TIME := T#500MS; // Tempo de debounce para K1 TonK1Timeout : TON; // Timeout para acionamento de K1 TimeK1Timeout : TIME := T#10S;
debouncedK2 : BOOL := FALSE; // flag auxiliar informando que K2_in está estável em 1 TonDebounceK2 : TON; // timer para debounce de bk2 TimeDebounceK2 : TIME := T#500MS; // tempo de debounce para leitura de K2_in TonK2Timeout : TON; // Timeout para acionamento de K2 TimeK2Timeout : TIME := T#10S;
cmdK01 : BOOL := FALSE; // comandos calculados por ciclo e aplicados no final auxRed : BOOL := FALSE; auxYellow : BOOL := FALSE; auxGreen : BOOL := FALSE; auxK1_in : BOOL; // entradas digitais lidas no inicio da função auxK2_in : BOOL; indice : UINT;
// Variáveis para o Master 01 (COM1) eDeviceState01 : DED.DEVICE_STATE; // Para guardar o estado retornado xDiagInfoIsAvailable01 : BOOL; // Para guardar a saída xDiagnosisInfoAvailable eError01 : DED.ERROR; // Para guardar o código de erro xMaster01IsReady : BOOL; // Nosso booleano final de "pronto"
// Variáveis para o Master 02 (COM2) eDeviceState02 : DED.DEVICE_STATE; // Para guardar o estado retornado xDiagInfoIsAvailable02 : BOOL; // Para guardar a saída xDiagnosisInfoAvailable eError02 : DED.ERROR; // Para guardar o código de erro xMaster02IsReady : BOOL; // Nosso booleano final de "pronto"
END_VAR

// ═══════════════════════════════════════════════════════════════
// 1. RESET DE ESTADO
// ═══════════════════════════════════════════════════════════════

GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := FALSE;
diagnosticCode := 0;

// ═══════════════════════════════════════════════════════════════
// 2. CONVERSÃO DE ESCALAS
// ═══════════════════════════════════════════════════════════════

CASE Meas_Device OF 
	
	E_MeasDeviceType.CHINT_DTSU666 :
	 
		Ua  := valorLido.EmReal.Ua * 0.1;				// em Volts
		Ub  := valorLido.EmReal.Ub * 0.1;				// em Volts
		Uc  := valorLido.EmReal.Uc * 0.1;				// em Volts
		
		Ia  := valorLido.EmReal.Ia * 0.001;				// em Amperes
		Ib  := valorLido.EmReal.Ib * 0.001;				// em Amperes
		Ic  := valorLido.EmReal.Ic * 0.001;				// em Amperes
		
		Pt  := valorLido.EmReal.Pt *0.0001;				// kW
		Pa  := valorLido.EmReal.Pa *0.0001;				// kW
		Pb  := valorLido.EmReal.Pb *0.0001;				// kW
		Pc  := valorLido.EmReal.Pc *0.0001;				// kW
		
		Qt  := valorLido.EmReal.Qt *0.0001;				// kvar
		Qa  := valorLido.EmReal.Qa *0.0001;				// kvar
		Qb  := valorLido.EmReal.Qb *0.0001;				// kvar
		Qc  := valorLido.EmReal.Qc *0.0001;				// xkvar
		
		PFt := valorLido.EmReal.PFt *0.001;	
		PFa := valorLido.EmReal.PFa *0.001;
		PFb := valorLido.EmReal.PFb *0.001;
		PFc := valorLido.EmReal.PFc *0.001;

	E_MeasDeviceType.RELAY_URP1439TU :

		Ua  := valorLido.EmReal.Ua;				// em Volts
		Ub  := valorLido.EmReal.Ub;				// em Volts
		Uc  := valorLido.EmReal.Uc;				// em Volts
		
		Ia  := valorLido.EmReal.Ia;				// em Amperes
		Ib  := valorLido.EmReal.Ib;				// em Amperes
		Ic  := valorLido.EmReal.Ic;				// em Amperes
		
		PFt := valorLido.EmReal.PFt;	
		PFa := valorLido.EmReal.PFa;
		PFb := valorLido.EmReal.PFb;
		PFc := valorLido.EmReal.PFc;

	E_MeasDeviceType.RELAY_URP6000:
		// a definir
		
	E_MeasDeviceType.RELAY_REMP_GD:
		// a definir

END_CASE

// ═══════════════════════════════════════════════════════════════
// 3. VALIDAÇÃO DE RANGES (SEM RETURN)
// ═══════════════════════════════════════════════════════════════
// validação de tensões

IF (Ua < GVL_Persis.VMIN) OR (Ua > GVL_Persis.VMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_VOLTAGE_A_RANGE,bRaised:=TRUE,rParam1:=Ua,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (Ub < GVL_Persis.VMIN) OR (Ub > GVL_Persis.VMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_VOLTAGE_B_RANGE,bRaised:=TRUE,rParam1:=Ub,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (Uc < GVL_Persis.VMIN) OR (Uc > GVL_Persis.VMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_VOLTAGE_C_RANGE,bRaised:=TRUE,rParam1:=Uc,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF

// validação de correntes
IF (ABS(Ia) > GVL_Persis.IMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_CURRENT_A_RANGE,bRaised:=TRUE,rParam1:=Ia,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(Ib) > GVL_Persis.IMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_CURRENT_B_RANGE,bRaised:=TRUE,rParam1:=Ib,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(Ic) > GVL_Persis.IMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_CURRENT_C_RANGE,bRaised:=TRUE,rParam1:=Ic,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF

// validação de potencias ativas
IF (ABS(Pt) > GVL_Persis.PMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PT_RANGE,bRaised:=TRUE,rParam1:=Pt,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(Pa) > GVL_Persis.PMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PA_RANGE,bRaised:=TRUE,rParam1:=Pa,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(Pb) > GVL_Persis.PMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PB_RANGE,bRaised:=TRUE,rParam1:=Pb,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(Pc) > GVL_Persis.PMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PC_RANGE,bRaised:=TRUE,rParam1:=Pc,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF

// validação de potencias reativas
IF (ABS(Qt) > GVL_Persis.QMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_QT_RANGE,bRaised:=TRUE,rParam1:=Qt,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(Qa) > GVL_Persis.QMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_QA_RANGE,bRaised:=TRUE,rParam1:=Qa,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(Qb) > GVL_Persis.QMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_QB_RANGE,bRaised:=TRUE,rParam1:=Qb,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(Qc) > GVL_Persis.QMAX) THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_QC_RANGE,bRaised:=TRUE,rParam1:=Qc,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
	
// validação do fator das potencias
	
IF (ABS(PFt) < PFMIN) OR (ABS(PFt) >PFMAX)  THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PFT_RANGE,bRaised:=TRUE,rParam1:=PFt,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(PFa) < PFMIN) OR (ABS(PFa) >PFMAX)  THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PFA_RANGE,bRaised:=TRUE,rParam1:=PFa,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(PFb) < PFMIN) OR (ABS(PFb) >PFMAX)  THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PFB_RANGE,bRaised:=TRUE,rParam1:=PFb,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF
IF (ABS(PFc) < PFMIN) OR (ABS(PFc) >PFMAX)  THEN
    GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
	FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PFC_RANGE,bRaised:=TRUE,rParam1:=PFc,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
END_IF

// ═══════════════════════════════════════════════════════════════
// 4. VALIDAÇÃO CRUZADA (SÓ SE NÃO HOUVER ERRO AINDA)
// ═══════════════════════════════════════════════════════════════

IF NOT GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR THEN
	// Só valida se Pa significativo (ex: > 1 kW)
	IF ABS(Pa) > 1.0 THEN
		Calculado := Ua * Ia * PFa / 1000;
		IF ABS(Pa - Calculado) > (ABS(Pa) * Tolerancia) THEN  // ✅ Usa Pa, não Calculado
			GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
			FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PA_XCHECK_FAIL,bRaised:=TRUE,rParam1:=Pa,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
		END_IF
	END_IF
	
	// Repetir para Pb e Pc
	IF ABS(Pb) > 1.0 THEN
		Calculado := Ub * Ib * PFb / 1000;
		IF ABS(Pb - Calculado) > (ABS(Pb) * Tolerancia) THEN
			GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
			FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PB_XCHECK_FAIL,bRaised:=TRUE,rParam1:=Pb,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
		END_IF
	END_IF
	
	IF ABS(Pc) > 1.0 THEN
		Calculado := Uc * Ic * PFc / 1000;
		IF ABS(Pc - Calculado) > (ABS(Pc) * Tolerancia) THEN
			GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
			FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PC_XCHECK_FAIL,bRaised:=TRUE,rParam1:=Pc,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
		END_IF
	END_IF
	// Pt = Pa + Pb + Pc
	SomaP := Pa + Pb + Pc;
	IF ABS(Pt) > 1.0 THEN  // ✅ Só valida se significativo
		IF ABS(Pt - SomaP) > (ABS(Pt) * Tolerancia) THEN  // ✅ Usa Pt
			GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
			FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PT_XCHECK_FAIL,bRaised:=TRUE,rParam1:=Pt,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
		END_IF
	END_IF
	
	// FPt com base nas potencias ativas e reativas
	SomaQ:=Qa + Qb + Qc;
	Calculado := SQRT((SomaP * SomaP)+ (SomaQ * SomaQ));
	IF Calculado > 10 THEN 									// 1 kva
		Calculado := SomaP / Calculado;
		IF ABS(PFt - Calculado) > 0.05 THEN
			GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
			FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_PFT_XCHECK_FAIL,bRaised:=TRUE,rParam1:=PFt,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
		END_IF
	END_IF
END_IF;

// ═══════════════════════════════════════════════════════════════
// 5. DETECÇÃO DE CONGELAMENTO (OPCIONAL)
// ═══════════════════════════════════════════════════════════════
IF NOT GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR THEN
	IF ABS(Pt - Pt_last) < 1.0 THEN  // < 1 kW de variação
		frozen_count := frozen_count + 1;
	ELSE
		frozen_count := 0;
	END_IF
	
	IF frozen_count > FREEZE_THRESHOLD THEN
		GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR := TRUE;
		FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_FROZEN,bRaised:=TRUE,rParam1:=Pt,rParam2:=0.0,uMachState:= GVL_Main.uMachineState);
	END_IF
END_IF

Pt_last := Pt;
// ═══════════════════════════════════════════════════════════════
// 6. TRATAMENTO FINAL DE ERRO/SUCESSO
// ═══════════════════════════════════════════════════════==══════
IF GVL_ALARM_MANAGER.ALARM_MEAS_RANGE_ERROR THEN
	
    nErrors := MIN(nErrors + 1, 5);	// Clamp em 5
    bDadosOK := FALSE;  // Dado atual é inválido
    
    IF nErrors >= 5 THEN
        bPoucosErros := FALSE;   	// 🚨 Degradação crítica
    ELSE
        bPoucosErros := TRUE;    	// ⚠️ Ainda tolerável (1-4 erros)
    END_IF    
    // ❌ NÃO atualiza variáveis globais (mantém último valor válido)
    // ❌ NÃO reseta filtro (preserva estado anterior)  
ELSE
	// 1. Decrementa contador de erros (recuperação gradual)
    IF nErrors > 0 THEN
        nErrors := nErrors - 1;
    END_IF
    
    bDadosOK := TRUE;
    bPoucosErros := TRUE;
    diagnosticCode := 0;
	
    // 2. FILTRO PASSA-BAIXA (Suavização de Medição)
    // ─────────────────────────────────────────────────────────
    IF bFirstRun THEN
        Pt_filt := Pt;
        Qt_filt := Qt;
        PFt_filt := PFt;
        bFirstRun := FALSE;
    ELSE
		// Filtro exponencial: y[n] = α·x[n] + (1-α)·y[n-1]
        // ALPHA configurável (ex: 0.25 → ~3s para 95% do valor)
        Pt_filt := GVL_Persis.ALPHA * Pt + (1.0 - GVL_Persis.ALPHA) * Pt_filt;
        Qt_filt := GVL_Persis.ALPHA * Qt + (1.0 - GVL_Persis.ALPHA) * Qt_filt;
        PFt_filt := GVL_Persis.ALPHA * PFt + (1.0 - GVL_Persis.ALPHA) * PFt_filt;
    END_IF
	
	// 3. ATUALIZAÇÃO DE VARIÁVEIS GLOBAIS
    // ──────────────────────────────────────────────────────────
	GVL_Main.Ua  := Ua;				// em Volts
	GVL_Main.Ub  := Ub;				// em Volts
	GVL_Main.Uc  := Uc;				// em Volts
	
	GVL_Main.Ia  := Ia;				// em Amperes
	GVL_Main.Ib  := Ib;				// em Amperes
	GVL_Main.Ic  := Ic;				// em Amperes
	
	// Potência Ativa (FILTRADA para controle)
	GVL_Main.Pt  := Pt_filt;			// kW
	GVL_Main.Pa  := Pa;				// kW
	GVL_Main.Pb  := Pb;				// kW
	GVL_Main.Pc  := Pc;				// kW
	
	// Potência Reativa (FILTRADA para controle de PF)
	GVL_Main.Qt  := Qt_filt;			// kvar
	GVL_Main.Qa  := Qa;				// kvar
	GVL_Main.Qb  := Qb;				// kvar
	GVL_Main.Qc  := Qc;				// kvar
    
    // Fator de Potência (FILTRADO para controle)
	GVL_Main.PFt := PFt_filt;				
	GVL_Main.PFa := PFa;
	GVL_Main.PFb := PFb;
	GVL_Main.PFc := PFc;

END_IF

// Chama o FB de display todo ciclo (ele só recalcula quando HMI_bRefresh der pulso)
fbEventDisplay(
    pEventLog   := GVL_Main.fbEventLog,     // referência ao ring buffer
    bRefresh    := HMI_bRefresh,   			// pulso da IHM
    nPageOffset := HMI_nPage       			// página selecionada
);


// ════════════════════════════════════════════════════════════════
// MÁQUINA DE ESTADOS PRINCIPAL
// ════════════════════════════════════════════════════════════════
CASE MachineState OF
	
// ────────────────────────────────────────────────────────────────
// START: Inicialização (fbStart + K1/K2)
E_MachineState.START:
    fbStart();  // Chamada do bloco de inicialização
	
	CASE fbStart.stState OF
		E_StartupStatus.stInit,
        E_StartupStatus.stWait_K1,
        E_StartupStatus.stWait_K2:
        	// Permanece em START
        E_StartupStatus.stDone:
			// Inicialização única (executada 1x após power-on)
			FailState := E_FailState.FS_INIT;
			FaultLatch := FALSE;
			StopLatch := FALSE;
			ton15s(IN := FALSE);
			ton30s(IN := FALSE);
			ton2s(IN := FALSE);
            (* Inicialização concluída – segue para leitura *)		
            MachineState := E_MachineState.READ;
		E_StartupStatus.stError:
			MachineState := E_MachineState.STOP;					// ocorreu erro na inicialização do sistema
		
{#ifdef DEBUG_MODE}			
MachineState := E_MachineState.CONTROL;
auxvalor:=0;
{#endif}
	END_CASE;

// ────────────────────────────────────────────────────────────────
// READ: Leitura do Medidor
E_MachineState.READ:

    // Marca início do ciclo apenas uma vez ao entrar em READ
    IF bFirstScanRead THEN
        tCycleStart := SysTimeCore.SysTimeGetMs();
        bFirstScanRead := FALSE;
    END_IF;	
  	fbReadMeas(tTimeout := T#250MS,trigInv := GVL_Main.trigMedidor100,pSlave  := GVL_Main.pMedidor100^);
	
	// avalia estado do Medidor a cada ciclo
	MedidorOK:=FALSE;
	
	CASE fbReadMeas.result OF
		E_ModbusResult.DONE:
			ContaMeasModBusErros:= 0;
			ContaMeasModBusTimeOut:= 0;
			fbValidaDados(Meas_Device:=GVL_Persis.MeasDeviceType);
			MedidorOK:=fbValidaDados.bDadosOK;
			GVL_ALARM_MANAGER.ALARM_MEAS_USING_LAST_VALUEU:=fbValidaDados.bPoucosErros;
			GVL_ALARM_MANAGER.CRIT_MEAS_PERSISTENT_FAIL:=(NOT MedidorOK AND NOT fbValidaDados.bPoucosErros);
			IF MedidorOK THEN
				MachineState := E_MachineState.CONTROL;
				FC_LogEvent(eCode:=E_EventCode.INFO_MEAS_READ_OK,bRaised:= TRUE,rParam1:= 0.0,rParam2:= 0.0,uMachState := GVL_Main.uMachineState);
			ELSE
				// ❌ Dados inválidos
				IF fbValidaDados.bPoucosErros THEN
					// Erro isolado → continua sem mudar o controle - perde o ciclo de controle
					MachineState := E_MachineState.IDLE;
					FC_LogEvent(eCode:= E_EventCode.ALARM_MEAS_USING_LAST_VALUE,bRaised:= TRUE,rParam1:= 0.0,rParam2:= 0.0,uMachState := GVL_Main.uMachineState);
				ELSE
					// Muitos erros → degradado
					MachineState := E_MachineState.FAIL;
					FC_LogEvent(eCode:= E_EventCode.CRIT_MEAS_PERSISTENT_FAIL,bRaised:= TRUE,rParam1:= 0.0,rParam2:= 0.0,uMachState := GVL_Main.uMachineState);
				END_IF
			END_IF
			
		E_ModbusResult.ERRO:
			ContaMeasModBusErros:= ContaMeasModBusErros + 1;
			GVL_ALARM_MANAGER.CRIT_MEAS_MODBUS_ERRO:=(ContaMeasModBusErros > GVL_Main.MAX_Meas_MODBUS_ERROS);
			IF GVL_ALARM_MANAGER.CRIT_MEAS_MODBUS_ERRO THEN					// permite seguir sem parar se acontecerem erros abaixo do maximo
				MachineState := E_MachineState.FAIL;
				FC_LogEvent(eCode:= E_EventCode.CRIT_MEAS_MODBUS_ERRO,bRaised:= TRUE,rParam1:=TO_REAL(ContaMeasModBusErros),rParam2:= 0.0,uMachState:=GVL_Main.uMachineState);
			ELSE
				MachineState := E_MachineState.IDLE;
				FC_LogEvent(eCode:= E_EventCode.ALARM_MEAS_MODBUS_ERROR,bRaised:= TRUE,rParam1:=TO_REAL(ContaMeasModBusErros),rParam2:= 0.0,uMachState:=GVL_Main.uMachineState);
			END_IF
			
		E_ModbusResult.TIMEOUT: 
			ContaMeasModBusTimeOut:= ContaMeasModBusTimeOut + 1;
			GVL_ALARM_MANAGER.CRIT_MEAS_MODBUS_TIMEOUT:=(ContaMeasModBusTimeOut > GVL_Main.MAX_Meas_MODBUS_TIMEOUTS);
			IF GVL_ALARM_MANAGER.CRIT_MEAS_MODBUS_TIMEOUT THEN				// permite seguir sem parar se acontecerem TimeOut abaixo do maximo
				MachineState := E_MachineState.FAIL;
				FC_LogEvent(eCode:=E_EventCode.CRIT_MEAS_MODBUS_TIMEOUT,bRaised:=TRUE,rParam1:=TO_REAL(ContaMeasModBusTimeOut),rParam2:=0.0,uMachState := GVL_Main.uMachineState);
			ELSE
				MachineState := E_MachineState.IDLE;
				FC_LogEvent(eCode:=E_EventCode.ALARM_MEAS_MODBUS_TIMEOUT,bRaised:=TRUE,rParam1:=TO_REAL(ContaMeasModBusTimeOut),rParam2:=0.0,uMachState := GVL_Main.uMachineState);
			END_IF
	
    END_CASE

// ────────────────────────────────────────────────────────────────
// CONTROL: Cálculo de Setpoints
E_MachineState.CONTROL:
// Calcula setpoints (PI + droop)

IF GVL_Main.InstalledPower <= 0.0 THEN
	// SINALIZAR ERRO
	MachineState := E_MachineState.STOP;
ELSE
	fbControle(bReset:=FALSE);  
END_IF

    // Inicialização da Escrita
    IF GVL_Main.NInversoresCOM01 > 0 THEN
        InvIndexCOM1 := 1;
        DoneCOM1 := FALSE;
    ELSE
        DoneCOM1 := TRUE;
		// SINALIZA ERRO
    END_IF;

    IF GVL_Main.NInversoresCOM02 > 0 THEN
        InvIndexCOM2 := 1;
        DoneCOM2 := FALSE;
    ELSE
        DoneCOM2 := TRUE;
		// SINALIZA ERRO
    END_IF;

    MachineState := E_MachineState.WRITE;
{#ifdef DEBUG_MODE}	
MachineState := E_MachineState.CONTROL;
{#endif}

// ────────────────────────────────────────────────────────────────
// WRITE: Envia Comandos aos Inversores
E_MachineState.WRITE:
// Envia comandos aos inversores

					// ───── DEBUG ───────────────────────────────────────────────
					{#ifdef DEBUG_MODE}	
					IF bFirstScanRead THEN
						tCycleStart := SysTimeCore.SysTimeGetMs();
						bFirstScanRead := FALSE;
					END_IF
					{#endif}
					// ───── DEBUG ───────────────────────────────────────────────

	DoneCOM1 := (InvIndexCOM1 > GVL_Main.NInversoresCOM01);
	DoneCOM2 := (InvIndexCOM2 > GVL_Main.NInversoresCOM02);

    // COM1 (inversores 1..15)
    IF InvIndexCOM1 <= GVL_Main.NInversoresCOM01 THEN
        IF GVL_Persis.InvActivePower[InvIndexCOM1] > 0.0 THEN

					// ───── DEBUG ───────────────────────────────────────────────
					{#ifdef DEBUG_MODE}
					// medição do tempo de execução
					rTrigOn(CLK := GVL_Main.pInversores100[1]^.xBusy);
					fTrigOff(CLK := GVL_Main.pInversores100[15]^.xBusy);
					(* Borda de subida → início *)
					IF rTrigOn.Q AND (InvIndexCOM1=1)   THEN
						SysTimeCore.SysTimeGetUs(tStartCom);
						Gatilho := TRUE;  // libera nova medição
					END_IF
					(* Borda de descida → fim *)
					IF fTrigOff.Q AND Gatilho THEN
						SysTimeCore.SysTimeGetUs(tEndCom);
						tCom := tEndCom - tStartCom; 
						IF tCom>tMax THEN
							tMax:=tCom;
						END_IF
						Gatilho := FALSE;
					END_IF
					{#endif}
					// ───── DEBUG ───────────────────────────────────────────────
	
            fbWriteCH1(tTimeout := T#100MS,trigInv := GVL_Main.trigInvCOM100[InvIndexCOM1],pSlave  := GVL_Main.pInversores100[InvIndexCOM1]^);
			
			CASE fbWriteCH1.result OF
            	E_ModbusResult.DONE:
				
					InvIndexCOM1 := InvIndexCOM1 + 1;

					FC_LogEvent(eCode:=E_EventCode.INFO_CH1_WRITE_OK,bRaised:= TRUE,rParam1:= 0.0,rParam2:= 0.0,uMachState := GVL_Main.uMachineState);
				
				E_ModbusResult.ERRO:															// permite seguir sem parar se acontecerem erros abaixo do maximo
					ContaCH1ModBusErro:= ContaCH1ModBusErro + 1;
					GVL_ALARM_MANAGER.CRIT_CH1_MODBUS_ERRO:=(ContaCH1ModBusErro > GVL_Main.MAX_CH1_MODBUS_ERROS);
					IF GVL_ALARM_MANAGER.CRIT_CH1_MODBUS_ERRO THEN					
						MachineState := E_MachineState.FAIL;
						FC_LogEvent(eCode:= E_EventCode.CRIT_CH1_MODBUS_ERRO,bRaised:= TRUE,
							rParam1:=TO_REAL(ContaCH1ModBusErro),rParam2:=TO_REAL(InvIndexCOM1),uMachState:=GVL_Main.uMachineState);
					ELSE
						MachineState := E_MachineState.IDLE;
						FC_LogEvent(eCode:= E_EventCode.ALARM_CH1_MODBUS_ERRO,bRaised:= TRUE,
							rParam1:=TO_REAL(ContaCH1ModBusErro),rParam2:=TO_REAL(InvIndexCOM1),uMachState:=GVL_Main.uMachineState);
					END_IF
					InvIndexCOM1 := InvIndexCOM1 + 1;
					
				E_ModbusResult.TIMEOUT: 														// permite seguir sem parar se acontecerem TimeOut abaixo do maximo
					ContaCH1ModBusTimeOut:= ContaCH1ModBusTimeOut + 1;
					GVL_ALARM_MANAGER.CRIT_CH1_MODBUS_TIMEOUT:=(ContaCH1ModBusTimeOut > GVL_Main.MAX_CH1_MODBUS_TIMEOUTS);
					IF GVL_ALARM_MANAGER.CRIT_CH1_MODBUS_TIMEOUT THEN				
						MachineState := E_MachineState.FAIL;
						FC_LogEvent(eCode:=E_EventCode.CRIT_CH1_MODBUS_TIMEOUT,bRaised:=TRUE,
							rParam1:=TO_REAL(ContaCH1ModBusTimeOut),rParam2:=TO_REAL(InvIndexCOM1),uMachState := GVL_Main.uMachineState);
					ELSE
						MachineState := E_MachineState.IDLE;
						FC_LogEvent(eCode:=E_EventCode.ALARM_CH1_MODBUS_TIMEOUT,bRaised:=TRUE,
							rParam1:=TO_REAL(ContaCH1ModBusTimeOut),rParam2:=TO_REAL(InvIndexCOM1),uMachState := GVL_Main.uMachineState);
					END_IF
					InvIndexCOM1 := InvIndexCOM1 + 1;	
			
            END_CASE
        ELSE
            // pular inversor inativo
            InvIndexCOM1 := InvIndexCOM1 + 1;
        END_IF
    ELSE
        DoneCOM1 := TRUE;
    END_IF

    // COM2 (inversores 16..30)
    IF InvIndexCOM2 <= GVL_Main.NInversoresCOM02 THEN
        IF GVL_Persis.InvActivePower[InvIndexCOM2 + 15] > 0.0 THEN
			
            fbWriteCH2(tTimeout := T#100MS,trigInv := GVL_Main.trigInvCOM200[InvIndexCOM2],pSlave  := GVL_Main.pInversores200[InvIndexCOM2]^);

			CASE fbWriteCH2.result OF
            	E_ModbusResult.DONE:
				
					InvIndexCOM2 := InvIndexCOM2 + 1;
	
					FC_LogEvent(eCode:=E_EventCode.INFO_CH2_WRITE_OK,bRaised:= TRUE,rParam1:= 0.0,rParam2:= 0.0,uMachState := GVL_Main.uMachineState);
				
				E_ModbusResult.ERRO:															// permite seguir sem parar se acontecerem erros abaixo do maximo
					ContaCH2ModBusErro:= ContaCH2ModBusErro + 1;
					GVL_ALARM_MANAGER.CRIT_CH2_MODBUS_ERRO:=(ContaCH2ModBusErro > GVL_Main.MAX_CH2_MODBUS_ERROS);
					IF GVL_ALARM_MANAGER.CRIT_CH2_MODBUS_ERRO THEN					
						MachineState := E_MachineState.FAIL;
						FC_LogEvent(eCode:= E_EventCode.CRIT_CH2_MODBUS_ERRO,bRaised:= TRUE,
							rParam1:=TO_REAL(ContaCH2ModBusErro),rParam2:=TO_REAL(InvIndexCOM2),uMachState:=GVL_Main.uMachineState);
					ELSE
						MachineState := E_MachineState.IDLE;
						FC_LogEvent(eCode:= E_EventCode.ALARM_CH2_MODBUS_ERRO,bRaised:= TRUE,
							rParam1:=TO_REAL(ContaCH2ModBusErro),rParam2:=TO_REAL(InvIndexCOM2),uMachState:=GVL_Main.uMachineState);
					END_IF
					InvIndexCOM2 := InvIndexCOM2 + 1;
					
				E_ModbusResult.TIMEOUT: 														// permite seguir sem parar se acontecerem TimeOut abaixo do maximo
					ContaCH2ModBusTimeOut:= ContaCH2ModBusTimeOut + 1;
					GVL_ALARM_MANAGER.CRIT_CH2_MODBUS_TIMEOUT:=(ContaCH2ModBusTimeOut > GVL_Main.MAX_CH2_MODBUS_TIMEOUTS);
					IF GVL_ALARM_MANAGER.CRIT_CH2_MODBUS_TIMEOUT THEN				
						MachineState := E_MachineState.FAIL;
						FC_LogEvent(eCode:=E_EventCode.CRIT_CH2_MODBUS_TIMEOUT,bRaised:=TRUE,
							rParam1:=TO_REAL(ContaCH2ModBusTimeOut),rParam2:=TO_REAL(InvIndexCOM2),uMachState := GVL_Main.uMachineState);
					ELSE
						MachineState := E_MachineState.IDLE;
						FC_LogEvent(eCode:=E_EventCode.ALARM_CH2_MODBUS_TIMEOUT,bRaised:=TRUE,
							rParam1:=TO_REAL(ContaCH2ModBusTimeOut),rParam2:=TO_REAL(InvIndexCOM2),uMachState := GVL_Main.uMachineState);
					END_IF
					InvIndexCOM2 := InvIndexCOM2 + 1;	
			
            END_CASE
        ELSE
            // pular inversor inativo
            InvIndexCOM2 := InvIndexCOM2 + 1;
        END_IF
    ELSE
        DoneCOM2 := TRUE;
    END_IF

    // Fim da escrita
    IF DoneCOM1 AND DoneCOM2 THEN
        InvIndexCOM1 := 1;
        InvIndexCOM2 := 1;
		ContaCH1ModBusErro:=0;
		ContaCH1ModBusTimeOut:=0;
		ContaCH2ModBusErro:=0;
		ContaCH2ModBusTimeOut:=0;	

    END_IF

// ────────────────────────────────────────────────────────────────
// IDLE: Aguarda Completar Ciclo (1s)			
E_MachineState.IDLE:
//  Aguarda completar período de ciclo (1 segundo) depois de
	IF tCycleStart <> 0 THEN
    	tElapsed := SysTimeCore.SysTimeGetMs() - tCycleStart; 					// Calcula tempo desde início do ciclo
	END_IF;
	IF tElapsed >= GVL_Main.CYCLE_TIME_MS THEN
		MachineState := E_MachineState.READ;
		bFirstScanRead := TRUE;
       	// Atualiza estatísticas
       	IF tElapsed > MaxCycleTime THEN
           MaxCycleTime := tElapsed;
       	END_IF;  

	GVL_ALARM_MANAGER.ALARM_SCAN_OVERRUN:=(tElapsed > GVL_Main.CYCLE_TIME_TOLERANCE);
	IF GVL_ALARM_MANAGER.ALARM_SCAN_OVERRUN THEN
		ScanOverrunCount := ScanOverrunCount + 1;
		GVL_ALARM_MANAGER.CRIT_SCAN_OVERRUN:=(ScanOverrunCount >= 3);
		FC_LogEvent(eCode:=E_EventCode.WARN_SCAN_OVERRUN,bRaised:=TRUE,
							rParam1:=0.0,rParam2:=0.0,uMachState := GVL_Main.uMachineState);
		IF GVL_ALARM_MANAGER.CRIT_SCAN_OVERRUN THEN
		FC_LogEvent(eCode:=E_EventCode.CRIT_SCAN_OVERRUN,bRaised:=TRUE,
							rParam1:=0.0,rParam2:=0.0,uMachState := GVL_Main.uMachineState);
			MachineState := E_MachineState.FAIL;
			ScanOverrunCount := 0;
		END_IF
	ELSE
		ScanOverrunCount := 0;
	END_IF
{#ifdef DEBUG_MODE}
		MachineState := E_MachineState.CONTROL;
{#endif}
	END_IF;

// ────────────────────────────────────────────────────────────────
E_MachineState.FAIL:
// ESTADO FAIL — Redução forçada (norma DIS-NOR-033)
// ton15s: P > LPI + 10% Pnom por >15s → STOP
// ton30s: P > LPI por >30s → STOP

    // ══════════════════════════════════════════════════════════
    // TIMERS NORMATIVOS (monitorados TODO CICLO)
    // Cálculo do hard limit
	LPI_mag := ABS(GVL_Main.MaxExportLimit);
	Export_mag := MAX(0, -GVL_Main.Pt);
    HardLimit_mag := LPI_mag + (GVL_Main.InstalledPower * 0.1);
	
    // Mantém leitura do medidor (diagnóstico)
  	fbReadMeas(tTimeout := T#250MS,trigInv:=GVL_Main.trigMedidor100,pSlave:=GVL_Main.pMedidor100^);
	
	// ✅ CORREÇÃO: Atualiza MedidorOK dentro de FAIL
    MedidorOK:=fbValidaDados.bDadosOK;	
	
    // ── TIMER 15s: hard limit (P > LPI + 10% Pnom) ──

    ton15s(IN := Export_mag > HardLimit_mag, PT := T#15S);

    // ── TIMER 30s: exportação persistente (P > LPI) ──
    ton30s(IN := (Export_mag > LPI_mag), PT := T#30S);
	
    // ── Escalada para STOP ──
    IF ton15s.Q OR ton30s.Q THEN
		IF ton15s.Q THEN
			GVL_ALARM_MANAGER.CRIT_HARDLIMIT_15S:=ton15s.Q;
			FC_LogEvent(eCode:=E_EventCode.CRIT_HARDLIMIT_15S,bRaised:=TRUE,
				rParam1:=Export_mag,rParam2:=HardLimit_mag,uMachState := GVL_Main.uMachineState);
			// SINALIZA ERRO hard limit: P > LPI + 10% Pnom por >15s
		ELSIF ton30s.Q THEN
			GVL_ALARM_MANAGER.CRIT_EXPORT_OVER_LPI_30S:=ton30s.Q;
			FC_LogEvent(eCode:=E_EventCode.CRIT_EXPORT_OVER_LPI_30S,bRaised:=TRUE,
				rParam1:=Export_mag,rParam2:=LPI_mag,uMachState := GVL_Main.uMachineState);
			// SINALIZA ERRO exportação > LPI por >30s
		END_IF
        MachineState := E_MachineState.STOP;
        RETURN;
    END_IF

    // ══════════════════════════════════════════════════════════
    // SUB-ESTADOS SIMPLIFICADOS
    CASE FailState OF

        E_FailState.FS_INIT:
		
			// Sinalização
			GVL_Main.K4YellowOut := TRUE;
			GVL_Main.K5GreenOut := FALSE;
            // Reinicializa índices de escrita
            InvIndexCOM1 := 1;
            InvIndexCOM2 := 1;
            DoneCOM1 := FALSE;
            DoneCOM2 := FALSE;
			tonFailSafeRecovery(IN := FALSE);
			tonMedidorTimeout(IN := FALSE); 
            // Zera setpoints
            FOR i := 1 TO GVL_Main.NMAXINVERSORES DO
                GVL_Main.P_inv_kW[i] := 0.0;
                GVL_Main.P_inv_Percent[i] := 0.0;
                GVL_Main.Q_inv_kvar[i] := 0.0;
            END_FOR
            FailState := E_FailState.FS_FORCE_ZERO;
			// Sinaliza entrada em FAIL

        E_FailState.FS_FORCE_ZERO:
            // Escreve zero em todos os inversores (mesmo código do WRITE, simplificado)
            DoneCOM1 := (InvIndexCOM1 > GVL_Main.NInversoresCOM01);
            DoneCOM2 := (InvIndexCOM2 > GVL_Main.NInversoresCOM02);

            // COM1
            IF NOT DoneCOM1 THEN
                IF GVL_Persis.InvActivePower[InvIndexCOM1] > 0.0 THEN
					fbWriteCH1(tTimeout := T#100MS,trigInv := GVL_Main.trigInvCOM100[InvIndexCOM1],pSlave  := GVL_Main.pInversores100[InvIndexCOM1]^);

                    IF (fbWriteCH1.result = E_ModbusResult.DONE) OR
                       (fbWriteCH1.result = E_ModbusResult.ERRO) OR
                       (fbWriteCH1.result = E_ModbusResult.TIMEOUT) THEN
                        InvIndexCOM1 := InvIndexCOM1 + 1;
                    END_IF
                ELSE
                    InvIndexCOM1 := InvIndexCOM1 + 1;
                END_IF
            END_IF

            // COM2
            IF NOT DoneCOM2 THEN
                IF GVL_Persis.InvActivePower[InvIndexCOM2 + 15] > 0.0 THEN
					fbWriteCH2(tTimeout := T#100MS,trigInv := GVL_Main.trigInvCOM200[InvIndexCOM2],pSlave  := GVL_Main.pInversores200[InvIndexCOM2]^);

                    IF (fbWriteCH2.result = E_ModbusResult.DONE) OR
                       (fbWriteCH2.result = E_ModbusResult.ERRO) OR
                       (fbWriteCH2.result = E_ModbusResult.TIMEOUT) THEN
                        InvIndexCOM2 := InvIndexCOM2 + 1;
                    END_IF
                ELSE
                    InvIndexCOM2 := InvIndexCOM2 + 1;
                END_IF
            END_IF

            // Escrita completa?
            IF DoneCOM1 AND DoneCOM2 THEN
                FailState := E_FailState.FS_VALIDATE;
            END_IF

        E_FailState.FS_VALIDATE:
            // Recuperação: P dentro da zona de controle (≤ LPI + 10% Pnom)

            IF (fbReadMeas.result = E_ModbusResult.DONE) AND (Export_mag <= LPI_mag) AND MedidorOK THEN
			   
				// ✅ Condições OK: precisa manter a condição por 10 segundos para considerar recuperado
				tonFailSafeRecovery(IN := TRUE, PT := T#10S);
                IF tonFailSafeRecovery.Q THEN
                    // Recuperação automática
                    FailState := E_FailState.FS_INIT;
                    MachineState := E_MachineState.READ;
                    ton15s(IN := FALSE);
                    ton30s(IN := FALSE);
					tonMedidorTimeout(IN := FALSE);
            		tonFailSafeRecovery(IN := FALSE);
                    GVL_Main.K4YellowOut := FALSE;
                END_IF				
            ELSE
        		// ❌ Condições NÃO OK: reseta recuperação e testa timeout
                tonFailSafeRecovery(IN := FALSE);
				// ❌ TIMEOUT de medidor (5s sem leitura válida)
                tonMedidorTimeout(IN := (fbReadMeas.result <> E_ModbusResult.DONE), PT := T#5S);

                IF tonMedidorTimeout.Q THEN
					// ❌ STOP: Perda de visibilidade da planta
                    // Sinaliza  16#E3;
                    MachineState := E_MachineState.STOP;
					tonMedidorTimeout(IN := FALSE);  // Reset timer
        			RETURN;
                END_IF
            END_IF
    END_CASE

// ────────────────────────────────────────────────────────────────
E_MachineState.STOP:
    // ══════════════════════════════════════════════════════════
    // A. ENTRADA EM STOP (primeira execução)
    // ══════════════════════════════════════════════════════════
	
	// Sinaliza entrada em STOP
    IF NOT StopLatch THEN
        StopLatch := TRUE;
        StopEntryTime := SysTimeCore.SysTimeGetMs();
        K2_CheckDone := FALSE;
        sMessage_K2 := '';
		        
        // Trip imediato
        GVL_Main.K2_out := TRUE;					// aciona trip do disjuntor
        GVL_Main.K1_out := FALSE;					// desliga bobina de minima tensão ou contator se existente
        GVL_Main.K3RedOut := TRUE;				// indica disjuntor desligado e houve falha
        GVL_Main.K4YellowOut := FALSE;
        GVL_Main.K5GreenOut := FALSE;
	    // zera setpoints por segurança
        FOR i := 1 TO GVL_Main.NMAXINVERSORES DO
            GVL_Main.P_inv_kW[i] := 0.0;
            GVL_Main.P_inv_Percent[i] := 0.0;
            GVL_Main.Q_inv_kvar[i] := 0.0;
        END_FOR	
	
    END_IF
    
    // ══════════════════════════════════════════════════════════
    // B. VERIFICAÇÃO DE K2 (executa apenas 1 vez)
    // ══==══════════════════════════════════════════════════════
    IF NOT K2_CheckDone THEN
        ton2s(IN := TRUE, PT := T#2S);
        
        IF ton2s.Q THEN
            K2_CheckDone := TRUE;
            ton2s(IN := FALSE);
            
            IF GVL_Main.K2_in = TRUE THEN
                // Sinaliza 'STOP: ', 'CRITICO: K2 não abriu');
                FaultLatch := TRUE;
            ELSE
                // Sinaliza 'STOP:'STOP: ','K2 confirmado aberto');
                GVL_Main.K4YellowOut := TRUE;
            END_IF
        END_IF
    END_IF
    
    // ══════════════════════════════════════════════════════════
    // C. PROCESSAMENTO DE RESET MANUAL
    // ══════════════════════════════════════════════════════════
    rTrigReset(CLK := StopResetCmd);
    
	// Borda de subida: avalia condições básicas UMA VEZ
    IF rTrigReset.Q THEN
        // Avalia condições básicas
        bResetConditionsOK := (NOT GVL_Main.K2_in) AND (NOT FaultLatch) AND MedidorOK AND ComOK;      
		 IF NOT bResetConditionsOK THEN
			// Reset negado imediatamente
			StopResetCmd := FALSE;
			tonResetWindow(IN := FALSE);
			
			IF GVL_Main.K2_in THEN
				sResetDenialReason := 'K2 não está aberto';
			ELSIF FaultLatch THEN
				sResetDenialReason := 'FaultLatch ativo';
			ELSE
				sResetDenialReason := 'Medidor não OK';
			END_IF
			
			// Sinaliza 'STOP: 'STOP reset NEGADO: ', sResetDenialReason);
		END_IF
	END_IF       
        
	// Monitoramento CONTÍNUO enquanto StopResetCmd=TRUE e condições OK
	IF StopResetCmd AND bResetConditionsOK THEN
		// Timer acumula enquanto Pt dentro do limite
		IF GVL_Main.MaxExportLimit > 0.0 THEN
			tonResetWindow(IN := (GVL_Main.Pt >= -(GVL_Main.MaxExportLimit)), PT := T#10S);
		ELSE
			tonResetWindow(IN := (GVL_Main.Pt > 0.0), PT := T#10S);
		END_IF
		
		IF tonResetWindow.Q THEN
			// ✅ Reset aprovado após 10s
			StopLatch := FALSE;
			StopResetCmd := FALSE;
			bResetConditionsOK := FALSE;
			MachineState := E_MachineState.START;
			ton15s(IN := FALSE);
			ton30s(IN := FALSE);
			ton2s(IN := FALSE);
			tonResetWindow(IN := FALSE);
			// Sinaliza 'STOP: 'STOP reset manual OK';
		ELSE
			// Sinaliza 'STOP: 'Aguardando Pt estável por 10s...';
		END_IF	
	ELSE
		tonResetWindow(IN := FALSE);
	END_IF

END_CASE

// DEBUG
// {#define DEBUG_MODE}
PROGRAM MainProgram
(*
    Máquina de estados principal do controlador.
    Fluxo geral:
    START   -> READ    (quando fbStart termina com sucesso)
    READ    -> CONTROL (quando leitura Modbus do medidor conclui OK)
    READ    -> IDLE    (quando leitura falha, mas ainda não estourou RETRIES_READ)
    READ    -> FAIL    (quando leitura falha e estoura RETRIES_READ)
    CONTROL -> WRITE   (sempre, um ciclo de controle por leitura)
    WRITE   -> IDLE    (depois de tentar escrever em todos inversores, se não estourou RETRIES_WRITE)
    WRITE   -> FAIL    (se falhas de escrita estourarem RETRIES_WRITE)
    IDLE    -> READ    (quando completar 1 segundo de ciclo)
    FAIL    -> (aguarda ação do operador)
    STOP    -> (parada controlada, permanece travado)
*)

VAR
    fbStart         		: FB_Startup;        		// executa a inicialização
    fbControle      		: FB_Controle;		 		// módulo de controle
	fbChannel       		: ModbusChannel;
	fbReadMeas 				: FB_ModBus;
	fbWriteCH1 				: FB_ModBus;
    fbWriteCH2 				: FB_ModBus;
    fbEventDisplay  		: FB_EventDisplay;			// prepara dados para a IHM
	fbValidaDados			: FB_ValidaDados;	
	
	// ══════════════════════════════════════════════════════════
    // Máquina de Estados
    // ══════════════════════════════════════════════════════════
	MachineState 			: E_MachineState := E_MachineState.START;
	MachineState_Last 		: E_MachineState := E_MachineState.START;
    FailState     			: E_FailState := E_FailState.FS_INIT;
	
	// ══════════════════════════════════════════════════════════
	// Variáveis manipuladas pela IHM
	// ══════════════════════════════════════════════════════════
 	HMI_bRefresh    		: BOOL;     // Botão "Refresh" na IHM (pulso)
    HMI_nPage       		: UINT;     // Página atual (0 = mais recente)
	
    // ══════════════════════════════════════════════════════════
    // STOP: Trip e Reset Manual
    // ══════════════════════════════════════════════════════════
    StopLatch         		: BOOL := FALSE;
    StopResetCmd      		: BOOL := FALSE;
    StopEntryTime     		: UDINT := 0;
    K2_CheckDone      		: BOOL := FALSE;
    sMessage_K2       		: STRING(100) := '';
    bResetConditionsOK		: BOOL := FALSE;
    sResetDenialReason		: STRING(255) := '';
    rTrigReset        		: R_TRIG;
    tonResetWindow    		: TON;
    
    // ══════════════════════════════════════════════════════════
    // Timers Normativos (DIS-NOR-033)
    // ══════════════════════════════════════════════════════════
    ton15s  				: TON;   // Hard limit > 15s → STOP
    ton30s  				: TON;   // Exportação > LPI por > 30s → STOP
    ton2s   				: TON;   // Confirmação K2 aberto

    // ══════════════════════════════════════════════════════════
    // Health Monitoring
    // ══════════════════════════════════════════════════════════
    MedidorOK         		: BOOL := FALSE;
    ComOK             		: BOOL := FALSE;
    ComOK_COM1        		: BOOL := TRUE;
    ComOK_COM2        		: BOOL := TRUE;
    InvOnlineCount    		: UINT := 0;
    ScanOverrunCount  		: UINT := 0;
	FaultLatch        		: BOOL := FALSE;
	
    // ══════════════════════════════════════════════════════════
    // Limites Calculados
    // ══════════════════════════════════════════════════════════
    LPI_per_phase_kW  		: REAL := 0.0;
    HardLimit_mag     		: REAL := 0.0;
    LPI_mag			  		: REAL;
	Export_mag		  		: REAL;
    // ══════════════════════════════════════════════════════════
    // Validação Cruzada
    // ══════════════════════════════════════════════════════════
    Pt_Last           		: REAL := 0.0;
    P_inv_sum         		: REAL := 0.0;
    
    // ══════════════════════════════════════════════════════════
    // Leitura medidor
    // ══════════════════════════════════════════════════════════
	ContaMeasModBusErros  	: UINT := 0;
	ContaMeasModBusTimeOut	: UINT := 0;

    // ══════════════════════════════════════════════════════════
    // Escrita em Inversores (Sequencial)
    // ══════════════════════════════════════════════════════════
    InvIndexCOM1      		: UINT := 1;
    InvIndexCOM2     		: UINT := 1;
    DoneCOM1          		: BOOL := FALSE;
    DoneCOM2          		: BOOL := FALSE;
    LastErrorIdxCOM1  		: UINT := 0;
    LastErrorIdxCOM2  		: UINT := 0;
    WriteErrorCOM1    		: BOOL := FALSE;
    WriteErrorCOM2    		: BOOL := FALSE;
	ContaCH1ModBusErro		: UINT := 0;
	ContaCH2ModBusErro		: UINT := 0;
	ContaCH1ModBusTimeOut	: UINT := 0;
	ContaCH2ModBusTimeOut	: UINT := 0;
    
    // ══════════════════════════════════════════════════════════
    // Temporização e Watchdog
    // ══════════════════════════════════════════════════════════
    tCycleStart       		: UDINT := 0;
    tCycleEnd         		: UDINT;
    tCycle            		: UDINT;
    tElapsed          		: UDINT;
    bFirstScanRead    		: BOOL := TRUE;
    MaxCycleTime      		: UDINT := 0;
    CycleTimeOverrunCount 	: UDINT := 0;

    // ══════════════════════════════════════════════════════════
    // FAIL_SAFE (STOP Timeout)
    // ══════════════════════════════════════════════════════════
    tonStopWrite      		: TON;
    tStopWrite        		: TIME := T#2S;
	tonFailSafeRecovery		: TON;   // tempo para recuperação ao normal
	tonMedidorTimeout		: TON;   // tempo que aguarda medidor sem leitura
	
    // ══════════════════════════════════════════════════════════
    // Debug/Monitor
    // ══════════════════════════════════════════════════════════
    valor             		: UN_Convert_Word_To_Real;
    auxvalor          		: REAL := 0;
    stStart, stEnd, stCiclo : SYSTIME;
    tStartCom, tCom, tEndCom: SYSTIME;
    tMax              		: SYSTIME := 0;
    Gatilho           		: BOOL := TRUE;
    rTrigOn           		: R_TRIG;
    fTrigOff          		: F_TRIG;
    Primeiravez       		: BOOL := TRUE;
    stCicloMax        		: SYSTIME := 0;
    i                 		: UINT;
    
END_VAR

{attribute 'qualified_only'}
// ════════════════════════════════════════════════════════════════════
// E_EventCode — Código unificado de eventos do PPC-GD
// ════════════════════════════════════════════════════════════════════
//
// FAIXAS DE CÓDIGOS:
//   0x0000          = Sem evento
//   0x1xxx          = INFO     (informações operacionais)
//   0x2xxx          = WARNING  (desvios toleráveis, sem ação de potência)
//   0x4xxx          = ALARM    (falhas que requerem atenção ou degradam)
//   0x8xxx          = CRITICAL (ações de segurança: FAIL_SAFE ou STOP)
//
// SUB-FAIXAS (2º nibble = módulo):
//   x0xx = Sistema / Geral
//   x1xx = Startup (FB_Startup)
//   x2xx = Medição (FB_ReadMedidor, FB_ValidaDadosRele)
//   x3xx = Comunicação inversores (FB_WriteInv)
//   x4xx = Controle (FB_Controle, FB_PowerController, FB_PIQ)
//   x5xx = Scheduler / Agenda
//   x6xx = Máquina de Estados (MainProgram)
//   x7xx = Proteção normativa (timers 15s/30s, hard-limit)
//   x8xx = STOP / Trip
//   x9xx = Reservado para expansão
//   xAxx = Erros gerados pelo Driver Modbus do Codesys
//
// Observação: códigos legados (ex-16#C1/C2/E1/E2/E3/F1) são referenciados
// por comentário e mapeados semanticamente, sem manter o mesmo valor numérico,
// para preservar a coerência de severidade por faixa.
// ════════════════════════════════════════════════════════════════════
TYPE E_EventCode :
(
    EVT_NONE                        := 16#0000,

    // ══════════════════════════════════════════════════════════════
    // INFO (0x1xxx) — registro operacional, sem ação
    // ══════════════════════════════════════════════════════════════

    // ── Startup ──
    INFO_STARTUP_BEGIN              := 16#1100,  // Inicialização iniciada
    INFO_SERIAL_COM_OK              := 16#1101,  // COM1 e COM2 prontos
    INFO_RTC_OK                     := 16#1102,  // Relógio lido com sucesso
    INFO_INVERTER_COUNT             := 16#1103,  // Contagem de inversores concluída
    INFO_INSTALLED_POWER            := 16#1104,  // Potência instalada calculada
    INFO_K1_CONFIRMED               := 16#1105,  // K1_in confirmado (debounce)
    INFO_K2_CONFIRMED               := 16#1106,  // K2_in confirmado (debounce)
    INFO_STARTUP_DONE               := 16#1107,  // Startup completo → operação

    // ── Operação normal ──
    INFO_MEAS_READ_OK            	:= 16#1200,  // Leitura do medidor OK
    INFO_MEAS_DATA_VALID         	:= 16#1201,  // Dados validados e filtro aplicado
    INFO_MEAS_RECOVERING            := 16#1202,  // contador nErrors reduzindo (opcional)

    // ── Escrita inversores (0x13xx)
    INFO_CH1_WRITE_OK               := 16#1300,  // Escrita no canal 01 OK
	INFO_CH2_WRITE_OK               := 16#1301,  // Escrita no canal 02 OK
	
    // ── Scheduler (0x15xx)
    INFO_SPECIAL_DATE_ACTIVE        := 16#1500,  // Data especial ativa na agenda
    INFO_ZERO_GRID_MODE             := 16#1501,  // Modo Zero Grid ativo

    // ── Recuperação / Reset ──
    INFO_CYCLE_COMPLETE             := 16#1600,  // Ciclo READ→CONTROL→WRITE→IDLE OK
    INFO_FAIL_RECOVERY              := 16#1601,  // Recuperação automática do FAIL
    INFO_STATE_CHANGE               := 16#1610,  // Transição de MachineState

    // ── STOP/Reset (0x18xx)
    INFO_STOP_K2_OPEN_CONFIRMED     := 16#1800,  // K2 confirmado aberto no STOP
    INFO_STOP_RESET_APPROVED        := 16#1801,  // Reset manual aprovado
    INFO_STOP_RESET_WAITING         := 16#1802,  // Aguardando Pt estável para reset

    // ══════════════════════════════════════════════════════════════
    // WARNING (0x2xxx) — desvio tolerável, sem ação de potência
    // ══════════════════════════════════════════════════════════════

    // ── Startup ──
    WARN_TC_POWER_NOT_SET           := 16#2100,  // TC_Power_kW não configurado
    WARN_NO_INVERSORES_COM02        := 16#2101,  // COM2 sem inversores (pode ser intencional)

    // ── Medição ──

    WARN_MEAS_USING_LAST_VALID      := 16#2200,  // Usando última medição válida
    WARN_MEAS_CROSS_CHECK_PA        := 16#2201,  // Validação cruzada Pa inconsistente
    WARN_MEAS_CROSS_CHECK_PB        := 16#2202,  // Validação cruzada Pb inconsistente
    WARN_MEAS_CROSS_CHECK_PC        := 16#2203,  // Validação cruzada Pc inconsistente
    WARN_MEAS_CROSS_CHECK_PT_SUM    := 16#2204,  // Pt ≠ Pa+Pb+Pc
    WARN_MEAS_CROSS_CHECK_PF        := 16#2205,  // PFt inconsistente com P/S
    WARN_MEAS_ERROR_ISOLATED        := 16#2206,  // Erro de medição isolado (1-4 erros)

    // ── Comunicação inversores ──
    WARN_WRITE_INV_ERROR            := 16#2300,  // Erro escrita em inversor individual
    WARN_WRITE_INV_TIMEOUT          := 16#2301,  // Timeout escrita em inversor individual

    // ── Controle ──
    WARN_P_ALLOC_SATURATED          := 16#2400,  // P alocado < P comandado
    WARN_Q_LIMITED_BY_SMAX          := 16#2401,  // Q limitado por Smax dos inversores
    WARN_PF_BELOW_TARGET            := 16#2402,  // PF < 0.92 (mas não por limite de S)
    WARN_PF_NOT_ACHIEVABLE          := 16#2403,  // PF impossível (banco de capacitor)
    WARN_PI_P_SATURATED             := 16#2404,  // PI de P saturado
    WARN_PI_Q_SATURATED             := 16#2405,  // PI de Q saturado
    WARN_PHASE_LIMITED              := 16#2406,  // Potência limitada por fase

    // ── Ciclo ──
    WARN_SCAN_OVERRUN               := 16#2600,  // Ciclo excedeu tolerância (1x)

          // ── STOP/reset
    WARN_STOP_RESET_DENIED          := 16#2800,  // Reset manual negado

    // ══════════════════════════════════════════════════════════════
    // ALARM (0x4xxx) — falha que requer atenção, pode degradar
    // ══════════════════════════════════════════════════════════════

    // ── Medição — Range ──
    ALARM_MEAS_VOLTAGE_A_RANGE      := 16#4200,  // Tensão fase A fora de faixa
    ALARM_MEAS_VOLTAGE_B_RANGE      := 16#4201,  // Tens  o fase B fora de faixa
    ALARM_MEAS_VOLTAGE_C_RANGE      := 16#4202,  // Tensão fase C fora de faixa
    ALARM_MEAS_CURRENT_A_RANGE      := 16#4203,  // Corrente fase A fora de faixa
    ALARM_MEAS_CURRENT_B_RANGE      := 16#4204,  // Corrente fase B fora de faixa
    ALARM_MEAS_CURRENT_C_RANGE      := 16#4205,  // Corrente fase C fora de faixa
    ALARM_MEAS_PT_RANGE             := 16#4206,  // Potência total fora de faixa
    ALARM_MEAS_PA_RANGE             := 16#4207,  // Potência fase A fora de faixa
    ALARM_MEAS_PB_RANGE             := 16#4208,  // Potência fase B fora de faixa
    ALARM_MEAS_PC_RANGE             := 16#4209,  // Potência fase C fora de faixa
    ALARM_MEAS_QT_RANGE             := 16#420A,  // Reativa total fora de faixa
    ALARM_MEAS_QA_RANGE             := 16#420B,  // Reativa fase A fora de faixa
    ALARM_MEAS_QB_RANGE             := 16#420C,  // Reativa fase B fora de faixa
    ALARM_MEAS_QC_RANGE             := 16#420D,  // Reativa fase C fora de faixa
    ALARM_MEAS_PFT_RANGE            := 16#420E,  // PF total fora de faixa
    ALARM_MEAS_PFA_RANGE            := 16#420F,  // PF fase A fora de faixa
    ALARM_MEAS_PFB_RANGE            := 16#4210,  // PF fase B fora de faixa
    ALARM_MEAS_PFC_RANGE            := 16#4211,  // PF fase C fora de faixa
    ALARM_MEAS_FROZEN               := 16#4212,  // Medição congelada (Pt sem variação)
    ALARM_MEAS_PT_XCHECK_FAIL       := 16#4213,  // Potência total fora de faixa
    ALARM_MEAS_PA_XCHECK_FAIL       := 16#4214,  // Potência fase A fora de faixa
    ALARM_MEAS_PB_XCHECK_FAIL       := 16#4215,  // Potência fase B fora de faixa
    ALARM_MEAS_PC_XCHECK_FAIL       := 16#4216,  // Potência fase C fora de faixa	
	ALARM_MEAS_PFT_XCHECK_FAIL      := 16#4217,  // PF total fora de faixa
	ALARM_Q_LIMITED_SURPASS			:= 16#4218,  // Deficit de Q superior a 20 % - necessário banco de capacitores
	ALARM_Q_LIMITED_REACHED			:= 16#4219,  // Q atingiu limite- pode ser necessário banco de capacitores
	ALARM_MEAS_USING_LAST_VALUE 	:= 16#4220,  // Usando última medição válida

    // ── Comunicação medidor ──
    ALARM_MEAS_MODBUS_ERROR      	:= 16#4221,  // Erro Modbus do medidor
    ALARM_MEAS_MODBUS_TIMEOUT       := 16#4222,  // Timeout leitura medidor

    // ── Comunicação inversores ──
    ALARM_CH1_MODBUS_ERRO           := 16#4300,  // Canal COM1 >50% falhas
    ALARM_CH2_MODBUS_ERRO           := 16#4301,  // Canal COM2 >50% falhas
    ALARM_CH1_MODBUS_TIMEOUT        := 16#4302,  // Canal COM1 TIMEOUT < 3x
    ALARM_CH2_MODBUS_TIMEOUT        := 16#4303,  // Canal COM2 TIMEOUT < 3x

	
	// Erros gerados pelo Driver Modbus do Codesys
    ALARM_MB_ILLEGAL_FUNC         	:= 16#4A01,  // O dispositivo escravo não suporta o código de função
    ALARM_MB_ILLEGAL_ADDR         	:= 16#4A02,  // O dispositivo escravo não suporta este deslocamento de registro
    ALARM_MB_ILLEGAL_VALUE        	:= 16#4A03,  // O valor a ser gravado não é válido
    ALARM_MB_SLAVE_FAILURE        	:= 16#4A04,  // Erro irrecuperável ao executar a solicitação
    ALARM_MB_ACKNOWLEDGE          	:= 16#4A05,  // Notificação de um dispositivo escravo de que uma operação demorada foi iniciada 
    ALARM_MB_SLAVE_BUSY           	:= 16#4A06,  // Notificação de um dispositivo escravo de que uma operação demorada está em andamento
    ALARM_MB_MEMORY_PARITY        	:= 16#4A08,  // Erro específico para os códigos de função 20 e 21
    ALARM_MB_GW_PATH_UNAVAIL      	:= 16#4A0A,  // Erro específico ao usar dispositivos atrás de um gateway (Gateway mal configurado/ocupado)
    ALARM_MB_GW_DEVICE_FAIL       	:= 16#4A0B,  // Erro específico ao usar dispositivos atrás de um gateway (Dispositivo não responde)
    ALARM_MB_RESPONSE_TIMEOUT     	:= 16#4AA1,  // Não houve resposta a tempo - timeout
    ALARM_MB_RESPONSE_CRC         	:= 16#4AA2,  // O checksum da resposta está incorreto
    ALARM_MB_WRONG_SLAVE          	:= 16#4AA3,  // A resposta não é do dispositivo escravo esperado
    ALARM_MB_WRONG_FC             	:= 16#4AA4,  // A resposta não corresponde ao código de função esperado
    ALARM_MB_TCP_WARMOR           	:= 16#4AA5,  // Erro na porta TCP. A solicitação não foi enviada.
    ALARM_MB_INVALID_DATA         	:= 16#4AA6,  // A resposta contém dados inválidos.
    ALARM_MB_INVALID_PROTOCOL     	:= 16#4AA7,  // A resposta não está no protocolo Modbus.
    ALARM_MB_INVALID_HEADER       	:= 16#4AA8,  // Algum campo do cabeçalho Modbus MBAP (Protocolo, Comprimento) é inválido.
    ALARM_MB_INVALID_PARAM        	:= 16#4AA9,  // Algum parâmetro de entrada da operação é inválido 
    ALARM_MB_UNDEFINED            	:= 16#4AFF,  // O resultado da solicitação é indefinido ou ainda desconhecido, por exemplo, o estado inicial.
	ALARM_MB_APP_ABORTED          	:= 16#4AB1,
    ALARM_MB_APP_TIMEOUT          	:= 16#4AB2,

    // ══════════════════════════════════════════════════════════════
    // CRITICAL (0x8xxx) — ação de segurança (FAIL_SAFE ou STOP)
    // ══════════════════════════════════════════════════════════════

    // ── Startup ──
    CRIT_SERIAL_INIT_FAILED         := 16#8100,  // COM1/COM2 não inicializou
    CRIT_RTC_FAILED                 := 16#8101,  // Falha leitura RTC
    CRIT_NO_INSTALLED_POWER         := 16#8102,  // Potência instalada = 0
    CRIT_K1_TIMEOUT                 := 16#8103,  // K1 não respondeu (timeout)

    // ── Medição ──
    CRIT_MEAS_PERSISTENT_FAIL       := 16#8200,  // ex-16#C1 Medição com falha persistente (≥5 erros)
    CRIT_MEAS_COM_FAIL           	:= 16#8201,  // ex-16#C2 Erro/Timeout Modbus medidor → FAIL
	CRIT_MEAS_MODBUS_TIMEOUT		:= 16#8202,  // Timeout Modbus medidor → FAIL
	CRIT_MEAS_MODBUS_ERRO			:= 16#8203,  // Erro Modbus medidor → FAIL

    // ── Comunicação inversores ──
    CRIT_INV_CHANNEL_FAIL           := 16#8300,  // ex-16#C2 Canal COM com falha total → FAIL
    CRIT_CH1_MODBUS_TIMEOUT        	:= 16#8301,  // Canal COM1 TIMEOUT 3x
    CRIT_CH2_MODBUS_TIMEOUT        	:= 16#8302,  // Canal COM2 TIMEOUT 3x
	CRIT_CH1_MODBUS_ERRO	       	:= 16#8303,  // Canal COM1 >50% falhas
    CRIT_CH2_MODBUS_ERRO        	:= 16#8304,  // Canal COM2 >50% falhas

    // ── Controle ──
    CRIT_INSTALLED_POWER_ZERO       := 16#8400,  // InstalledPower = 0 em runtime → STOP
	CRIT_INSTALLED_SMAX_ZERO  		:= 16#8401,    // Error: Potência reativa instalada = 0

    // ── Scheduller ──
    CRIT_RTC_READ_FAIL              := 16#8500,  // RTC falhou durante operação
    CRIT_SCHEDULE_INDEX_INVALID     := 16#8501,  // Índice dia/hora inválido

    // ── Watchdog ──
    CRIT_SCAN_OVERRUN               := 16#8600,  // ex-16#F1 3× overruns consecutivos → FAIL

    // ── Proteção normativa ──
    CRIT_HARDLIMIT_15S             	:= 16#8700,  // ex-16#E1 P > LPI+10%Pnom por >15s → STOP
    CRIT_EXPORT_OVER_LPI_30S        := 16#8701,  // ex-16#E2 P > LPI por >30s → STOP
    CRIT_MEDIDOR_TIMEOUT_IN_FAIL    := 16#8702,  // ex-16#E3 30s sem medição válida em FAIL → STOP

    // ── STOP / Trip ──
    CRIT_STOP_ENTRY                 := 16#8800,  // Entrada no estado STOP
    CRIT_K2_DID_NOT_OPEN            := 16#8801,  // K2 não abriu após 2s → FaultLatch
    CRIT_STATE_CORRUPTION           := 16#8802   // MachineState inválido

) UINT;
END_TYPE

{attribute 'qualified_only'}
{attribute 'strict'}
TYPE E_FailState :
(
    FS_INIT         := 0,  // Inicialização FAIL_SAFE
    FS_FORCE_ZERO   := 1,  // Forçar setpoint zero
    FS_WAIT_CONFIRM := 2,  // Aguardar confirmação escrita
    FS_VALIDATE     := 3,  // Validar geração zero
    FS_ESCALATE     := 4   // Escalar para STOP
) UINT;
END_TYPE

{attribute 'qualified_only'}
{attribute 'strict'}
TYPE E_MachineState :
(
	START       := 0,  // inicializa o sistema uma única vez
    IDLE        := 1,  // Aguardando condições de início
    READ        := 2,  // Lendo medidor
    CONTROL     := 3,  // Calculando setpoints
    WRITE       := 4,  // Enviando comandos inversores
    FAIL	    := 5,  // Redução forçada (sem trip)
    STOP        := 6   // Trip + latch (reset manual)
) UINT;
END_TYPE

{attribute 'qualified_only'}
{attribute 'strict'}
TYPE E_MeasDeviceType :
(
    NONE := 0,
    CHINT_DTSU666 := 1,
    RELAY_URP1439TU := 2,
    RELAY_URP6000 := 3,
	RELAY_REMP_GD := 4
) UINT;
END_TYPE

{attribute 'qualified_only'}
{attribute 'strict'}
TYPE E_StartupStatus :
(
  stInit,			(* inicializa variaveis *)
  stWait_K1,      	(* transição imediata quando o delay completa *)
  stWait_K2,       	(* mantém bK3_out; monitora bK2_in com debounce *)
  stDone,           (* sucesso: desliga bK3_out e liga bK4_out *)
  stError           (* erro: sinaliza e coloca saídas em estado seguro *)
);
END_TYPE

// ════════════════════════════════════════════════════════════════════
// ST_Event — Registro dos eventos para mostrar na tabela
// ════════════════════════════════════════════════════════════════════
// Tamanho estimado: 28 bytes (verificar alinhamento no target)
//
// CAMPOS:
//   tTimestamp  — Epoch UTC (UDINT, até 2106). Obtido via SysTimeRtcGet.
//   eCode      — Código do evento (E_EventCode). Identifica unicamente o que ocorreu.
//   bRaised    — TRUE = evento apareceu / FALSE = evento foi limpo.
//                Permite rastrear par raise/clear no histórico.
//   rParam1    — Valor de contexto #1 no momento do evento.
//                Ex: Pt medido (kW) quando hard-limit disparou.
//   rParam2    — Valor de contexto #2 no momento do evento.
//                Ex: limite violado (kW), ou índice do inversor.
//   uMachState — Estado da máquina (E_MachineState) no momento do registro.
//                Essencial para análise pós-mortem.
// ════════════════════════════════════════════════════════════════════
TYPE ST_EventEntry :
STRUCT
    tTimestamp      : UDINT;            // UTC epoch (segundos)
    eCode           : E_EventCode;      // UINT — código unificado do evento
    bRaised         : BOOL;             // TRUE=raise, FALSE=clear
    rParam1         : REAL;             // contexto numérico #1
    rParam2         : REAL;             // contexto numérico #2
    uMachState      : UINT;             // E_MachineState no instante do registro
END_STRUCT
END_TYPE

TYPE TTraceEntry :
STRUCT
        cyc         : UDINT;
        mode        : USINT;
        startEdge   : BOOL;
        xExecute    : BOOL;
        xAbort      : BOOL;
        xBusy       : BOOL;
        xDone       : BOOL;
        xError      : BOOL;
        xAborted    : BOOL;
        toQ         : BOOL;
        modbusErr   : UDINT;
        eResult     : E_ModbusResult;
    END_STRUCT
END_TYPE

TYPE UN_Convert_Word_To_Real :
	UNION
        Tw : ARRAY[0..1] OF WORD;
        Tr : REAL;
    END_UNION
END_TYPE

TYPE UN_Energia :
	UNION
        WordArray : ARRAY[0..11] OF WORD;
        EmReal    : ST_Energia;
    END_UNION
END_TYPE

TYPE UN_Medidor :
	UNION
        WordArray : ARRAY[0..43] OF WORD;
        EmReal    : ST_Rele;
    END_UNION
END_TYPE

TYPE UN_Rele :
	UNION
        WordArray : ARRAY[0..43] OF WORD;
        EmReal    : ST_Rele;
    END_UNION
END_TYPE

// ════════════════════════════════════════════════════════════════════
// FB_EventLog — Buffer rotativo de eventos em NVRAM
// ════════════════════════════════════════════════════════════════════
// Plataforma: WAGO CC100 / CODESYS V3.5 SP21 Patch 4
//
// RESPONSABILIDADES:
//   1. Armazenar eventos em ring buffer RETAIN (sobrevive a power-cycle)
//   2. Limitar a 1 escrita por chamada (proteção de NVRAM)
//   3. Fornecer último evento e contadores para HMI
//   4. Permitir leitura indexada para exportação/diagnóstico
//
// GARANTIAS:
//   - Nunca estoura array (índice clamped por MOD)
//   - Nunca aloca memória dinâmica
//   - Tempo de execução O(1) por chamada (sem loops)
//   - Não usa STRING em runtime
//
// USO:
//   fbEventLog.LogEvent(
//       eCode      := E_EventCode.CRIT_HARD_LIMIT_15S,
//       bRaised    := TRUE,
//       rParam1    := Global.Pt,
//       rParam2    := REAL#-500.0,   // limite violado
//       uMachState := UINT_TO_UINT(MachineState)
//   );
// ════════════════════════════════════════════════════════════════════
FUNCTION_BLOCK FB_EventLog
VAR RETAIN
    // ── Ring buffer persistente ──
    aBuffer         : ARRAY[0..(GVL_EventLog.MAX_EVENT_ENTRIES - 1)] OF ST_EventEntry;
    nHead           : UINT := 0;            // Próxima posição de escrita
    bWrapped        : BOOL := FALSE;        // TRUE = buffer já deu pelo menos uma volta completa
    nTotalLogged    : UDINT := 0;           // Contador total desde último factory reset (para telemetria)
END_VAR
VAR
    // ── Saídas para HMI / lógica externa (recalculadas a cada LogEvent) ──
    stLastEvent     : ST_EventEntry;        // Cópia do último evento registrado
    nCount          : UINT := 0;            // Quantas entradas válidas existem no buffer
    bOverflow       : BOOL := FALSE;        // Sinaliza que eventos antigos foram sobrescritos
END_VAR

GVL_Main.fbEventLog.LogEvent(
    eCode      := eCode,
    bRaised    := bRaised,
    rParam1    := rParam1,
    rParam2    := rParam2,
    uMachState := uMachState
);

FC_LogEvent := TRUE;

FUNCTION FC_LogEvent : BOOL
VAR_INPUT
    eCode      : E_EventCode;
    bRaised    : BOOL;
    rParam1    : REAL := 0.0;
    rParam2    : REAL := 0.0;
    uMachState : UINT := 0;
END_VAR

// ════════════════════════════════════════════════════════════════
// 0. VERIFICAÇÕES INICIAIS E INICIALIZAÇÃO
// ════════════════════════════════════════════════════════════════

// Fator de potência medido (valor absoluto)
PF_measured := ABS(GVL_Main.PFt);

// ════════════════════════════════════════════════════════════════
// 1. FB_SCHEDULER - Define Limite de Exportação
// ════════════════════════════════════════════════════════════════

IF GVL_Persis.OperationMode THEN
	GVL_Main.MaxExportLimit:=0;				// TRUE = Zero Grid (exportação zero)
ELSE
	fbScheduler();   						// Global.MaxExportLimit definido a partir das agendas de horarios no Scheduller
END_IF

// ────────────────────────────────────────────────────────────────
// 2. CONTROLADOR DE POTÊNCIA ATIVA (PI + Safety + Limites)
// ────────────────────────────────────────────────────────────────

fbPowerCtrl(
    ExportLimit_kW := GVL_Main.MaxExportLimit,
    Feedback_kW := GVL_Main.Pt,
    bReset := bReset
);

bP_limit_reached := fbPowerCtrl.bPhase_limited OR fbPowerCtrl.bSaturated;
// ════════════════════════════════════════════════════════════════
// 3. FB_FFQ - Feedforward de Q 
// ════════════════════════════════════════════════════════════════

// Calcula Q necessário para manter PF = 0.92 com a potência comandada
fbFFQ(
    P_active_kW := fbPowerCtrl.P_cmd_kW, 
    PF_target_abs := GVL_Persis.PF_target,
    PF_sign := 1.0                              // Indutivo (positivo)
);

Q_feedforward_kvar := fbFFQ.Q_reactive_kvar;  	

// ════════════════════════════════════════════════════════════════
// 4. FB_PIQ - Controle de Fator de Potência
// ════════════════════════════════════════════════════════════════

// Controlador PI de fator de potência
fbPIQ(
    SP := GVL_Persis.PF_target,         							// Setpoint de PF (0.92)
    PV := PF_measured,              							// PF medido (absoluto)
	Kp:= GVL_Persis.Kp_Q,
	Ki:= GVL_Persis.Ki_Q,
	CycleTime:= GVL_Main.ControlCycle,
    P_cmd := fbPowerCtrl.P_cmd_kW,     							// Comando de P (para referência)
    RampUp := GVL_Persis.RampUp_Q,      							// Rampa de subida (kvar/s)
    RampDown := GVL_Persis.RampDown_Q,  							// Rampa de descida (kvar/s)
    DeadbandAbs := GVL_Persis.Deadband_Q, 							// Zona morta de PF
    Reset := bReset,                 							// Reset
	bExternal_Saturated := bQ_limit_reached OR bP_limit_reached // FEEDBACK do ciclo anterior - calculado em fbQAlloc.
);

Q_cmd_kvar := Q_feedforward_kvar + fbPIQ.MV;  // Comando de Q em kvar

// Clamp superior: não pode exceder Q máximo dos inversores
IF Q_cmd_kvar > GVL_Main.Q_max_permitido THEN
    Q_cmd_kvar := GVL_Main.Q_max_permitido;
END_IF
// Clamp inferior: se PF_sign = indutivo, Q não pode ser negativo
IF Q_cmd_kvar < 0.0 THEN
    Q_cmd_kvar := 0.0;  // Não permite Q negativo (capacitivo) se não desejado
END_IF

// ════════════════════════════════════════════════════════════════
// 5. FB_PAlloc - Aloca P (PRIORIDADE MÁXIMA)
// ══════════���═════════════════════════════════════════════════════

fbPAlloc(
    P_total_cmd_kW := fbPowerCtrl.P_cmd_kW
);
// WARN_P_ALLOC_SATURATED = P alocado < P comandado
rPcmd_kW:= ABS(fbPowerCtrl.P_cmd_kW);
rPallocSum_kW:= ABS(fbPowerCtrl.P_cmd_kW);
IF rPcmd_kW < rPallocSum_kW THEN
	FC_LogEvent(eCode:=E_EventCode.WARN_P_ALLOC_SATURATED,bRaised:=TRUE,rParam1:=rPcmd_kW,rParam2:=rPallocSum_kW,uMachState := GVL_Main.uMachineState);
END_IF
GVL_Main.P_allocated_kW := fbPAlloc.P_allocated_kW;

// ════════════════════════════════════════════════════════════════
// 6. FB_QAlloc - Aloca Q 
// ════════════════════════════════════════════════════════════════

fbQAlloc(
    Q_total_cmd_kvar := Q_cmd_kvar
);

GVL_Main.Q_allocated_kvar := fbQAlloc.Q_allocated_kvar;

// Armazena flag de saturação para próximo ciclo
bQ_limit_reached := fbQAlloc.bQ_limit_reached;

GVL_ALARM_MANAGER.ALARM_Q_LIMITED_BY_SMAX := bQ_limit_reached;
IF GVL_ALARM_MANAGER.ALARM_Q_LIMITED_BY_SMAX THEN
	FC_LogEvent(eCode:=E_EventCode.WARN_Q_LIMITED_BY_SMAX,bRaised:=TRUE,rParam1:=Q_cmd_kvar,rParam2:=fbQAlloc.Q_allocated_kvar,uMachState := GVL_Main.uMachineState);
END_IF

// ════════════════════════════════════════════════════════════════
// 7. FB_Diagnostico - Gera diagnóstico completo
// ════════════════════════════════════════════════════════════════

fbDiagnostico(
    P_allocated_kW := fbPAlloc.P_allocated_kW,
    Q_commanded_kvar := Q_cmd_kvar,
    Q_allocated_kvar := fbQAlloc.Q_allocated_kvar,
    Q_capacity_kvar := fbQAlloc.Q_capacity_total,
    PF_measured := PF_measured,
    PF_achieved := fbQAlloc.PF_effective,
    bQ_limited := fbQAlloc.bQ_limit_reached
);

// ────────────────────────────────────────────────────────────────
// 8. STATUS DE PF
// ────────────────────────────────────────────────────────────────
GVL_ALARM_MANAGER.ALARM_PF_BELOW_TARGET:= (fbQAlloc.PF_effective < GVL_Persis.PF_target);
IF GVL_ALARM_MANAGER.ALARM_PF_BELOW_TARGET THEN
	FC_LogEvent(
		eCode:=E_EventCode.WARN_PF_BELOW_TARGET,
		bRaised:=TRUE,
		rParam1:=fbQAlloc.PF_effective,
		rParam2:=GVL_Persis.PF_target,
		uMachState := GVL_Main.uMachineState
		);
END_IF

// ════════════════════════════════════════════════════════════════
// 1. ARMAZENA VALORES BÁSICOS
// ════════════════════════════════════════════════════════════════

GVL_Main.P_generated_kW := P_allocated_kW;
GVL_Main.P_allocated_kW := P_allocated_kW;
GVL_Main.Q_commanded_kvar := Q_commanded_kvar;
GVL_Main.Q_allocated_kvar := Q_allocated_kvar;
GVL_Main.Q_available_kvar := Q_capacity_kvar;
GVL_Main.PF_measured := PF_measured;
GVL_Main.PF_achieved := PF_achieved;

// Q medido (do ponto de conexão)
GVL_Main.Q_measured_kvar := GVL_Main.Qt;  // Já convertido em kvar pelo FB_AjustaLeitura

// ════════════════════════════════════════════════════════════════
// 2. CALCULA DÉFICIT DE Q
// ════════════════════════════════════════════════════════════════

Q_deficit := Q_commanded_kvar - Q_allocated_kvar;
GVL_Main.Q_deficit_kvar := Q_deficit;

// Déficit percentual
IF ABS(Q_commanded_kvar) > 0.1 THEN
    Q_deficit_pct := (ABS(Q_deficit) / ABS(Q_commanded_kvar)) * 100.0;
ELSE
    Q_deficit_pct := 0.0;
END_IF
GVL_Main.Q_deficit_percent := Q_deficit_pct;

// ════════════════════════════════════════════════════════════════
// 3. CALCULA UTILIZAÇÃO DE S
// ════════════════════════════════════════════════════════════════

// S total disponível
S_total_avail := GVL_Main.InstalledSmax;
GVL_Main.S_total_available_kVA := S_total_avail;

// S total usado
S_total_used := SQRT((P_allocated_kW * P_allocated_kW) + (Q_allocated_kvar * Q_allocated_kvar));
GVL_Main.S_total_used_kVA := S_total_used;

// Utilização percentual
IF S_total_avail > 0.0 THEN
    GVL_Main.S_utilization_pct := (S_total_used / S_total_avail) * 100.0;
ELSE
    GVL_Main.S_utilization_pct := 0.0;
END_IF

// ════════════════════════════════════════════════════════════════
// 4. CALCULA UTILIZAÇÃO DE Q
// ════════════════════════════════════════════════════════════════

GVL_Main.Q_capacity_total_kvar := Q_capacity_kvar;

IF Q_capacity_kvar > 0.0 THEN
    GVL_Main.Q_utilization_pct := (ABS(Q_allocated_kvar) / Q_capacity_kvar) * 100.0;
ELSE
    GVL_Main.Q_utilization_pct := 0.0;
END_IF

// ════════════════════════════════════════════════════════════════
// 5. CALCULA TAMANHO DE BANCO DE CAPACITORES
// ════════════════════════════════════════════════════════════════

IF Q_deficit > 0.1 THEN
    // Adiciona 10% de margem
    bank_size := ABS(Q_deficit) * 1.1;
	bank_size := DINT_TO_REAL(TRUNC(bank_size / 5.0) + 1) * 5.0;
    GVL_Main.Capacitor_bank_size_kvar := bank_size;
    GVL_Main.Capacitor_bank_recommended := TRUE;
ELSE
    GVL_Main.Capacitor_bank_size_kvar := 0.0;
    GVL_Main.Capacitor_bank_recommended := FALSE;
END_IF

// ════════════════════════════════════════════════════════════════
// 6. DETERMINA STATUS DE PF
// ════════════════════════════════════════════════════════════════

IF PF_achieved >= GVL_Main.PF_target THEN
    GVL_Main.PF_OK := TRUE;
    GVL_Main.PFErro := FALSE;
    GVL_Main.PF_alarm_code := 0;  // OK
ELSE
    GVL_Main.PF_OK := FALSE;
    
    IF bQ_limited THEN
        GVL_Main.PFErro := TRUE;
        
        // Classifica severidade
        IF Q_deficit_pct > 20.0 THEN
            GVL_Main.PF_alarm_code := 2;  // Crítico
			FC_LogEvent(
				eCode:=E_EventCode.ALARM_Q_LIMITED_SURPASS,
				bRaised:=TRUE,
				rParam1:=0.0,
				rParam2:=0.0,
				uMachState := GVL_Main.uMachineState
				);
        ELSE
            GVL_Main.PF_alarm_code := 1;  // Aviso
			FC_LogEvent(
				eCode:=E_EventCode.ALARM_Q_LIMITED_REACHED,
				bRaised:=TRUE,
				rParam1:=0.0,
				rParam2:=0.0,
				uMachState := GVL_Main.uMachineState
				);
        END_IF
    ELSE
        // PF < 0.92 mas não por limite de Q (transitório)
        GVL_Main.PFErro := FALSE;
        GVL_Main.PF_alarm_code := 1;
    END_IF
END_IF

// ════════════════════════════════════════════════════════════════
// 7. ATUALIZA HISTÓRICO (OPCIONAL - implementar com timers)
// ════════════════════════════════════════════════════════════════

// Atualiza PF mínimo
IF PF_achieved < GVL_Main.PF_min_24h THEN
    GVL_Main.PF_min_24h := PF_achieved;
END_IF

// Atualiza déficit máximo
IF Q_deficit > GVL_Main.Q_deficit_max_24h THEN
    GVL_Main.Q_deficit_max_24h := Q_deficit;
END_IF

// Conta alarmes (incrementar quando alarme dispara pela primeira vez)
// (Implementar com edge detection)

(*
    ════════════════════════════════════════════════════════════════
    FB_Diagnostico - Diagnóstico de Fator de Potência
    ════════════════════════════════════════════════════════════════
    
    Gera diagnóstico completo do sistema de compensação de PF,
    incluindo alarmes, recomendações e estatísticas.
    
    ═══���════════════════════════════════════════════════════════════
*)

FUNCTION_BLOCK FB_Diagnostico
VAR_INPUT
    P_allocated_kW : REAL;
    Q_commanded_kvar : REAL;
    Q_allocated_kvar : REAL;
    Q_capacity_kvar : REAL;
    PF_measured : REAL;
    PF_achieved : REAL;
    bQ_limited : BOOL;
END_VAR

VAR
    Q_deficit : REAL;
    Q_deficit_pct : REAL;
    S_total_avail : REAL;
    S_total_used : REAL;
    bank_size : REAL;
    bank_size_int : DINT;  // ✅ DINT (não INT)
END_VAR

// ──────────────────────────────────��───────────────────────────
// Reset
// ──────────────────────────────────────────────────────────────
IF bReset THEN
    P_droop_kW := 0.0;
    RETURN;
END_IF

// ──────────────────────────────────────────────────────────────
// Lógica do droop
// ──────────────────────────────────────────────────────────────
IF NOT Enable THEN
    P_droop_kW := 0.0;
    RETURN;
END_IF

// Aplica deadband ao erro
erro := Error_kW;
IF ABS(erro) < Deadband_kW THEN
    erro := 0.0;
END_IF

P_cmd := K_droop * erro;

// Limite absoluto
IF P_cmd > P_max_kW THEN
    P_cmd := P_max_kW;
ELSIF P_cmd < -P_max_kW THEN
    P_cmd := -P_max_kW;
END_IF

P_droop_kW := P_cmd;

// 1. Proteção: se potência ativa é zero ou negativa, não há Q a calcular
IF P_active_kW <= 0.0 THEN
    Q_reactive_kvar := 0.0;
    RETURN;
END_IF

// Proteção: PF_target deve estar entre 0 e 1
IF PF_target_abs <= 0.0 OR PF_target_abs > 1.0 THEN
    Q_reactive_kvar := 0.0;
    RETURN;
END_IF

// 2. Q total necessário no ponto de conexão para PF = 0.92
// Método 1: usando tan(acos(PF))
// phi := ACOS(PF_target_abs);              // Ângulo de fase em radianos
// tan_phi := TAN(phi);                     // Tangente do ângulo
// Q_reactive_var := P_active_W * tan_phi;
// Método 2: Simplificado (mais eficiente, evita ACOS e TAN)
// tan(acos(x)) = sqrt(1 - x²) / x
tan_phi := SQRT(1.0 - (PF_target_abs * PF_target_abs)) / PF_target_abs;
Q_target := P_active_kW * tan_phi;

// atribuição correta
Q_reactive_kvar := Q_target;

// 3. Aplica o sinal (Indutivo = positivo, Capacitivo = negativo)
// Nota: Para controle de exportação, normALARMente usamos indutivo (Q positivo)
IF PF_sign < 0.0 THEN
    Q_reactive_kvar := -Q_reactive_kvar;  // Capacitivo
END_IF

// Resultado: Q_reactive_var é o Q MÍNIMO para atingir PF_target
// - Se injetar menos Q: PF > PF_target (melhor)
// - Se injetar mais Q: PF < PF_target (pior)
// - Se injetar exatamente Q: PF = PF_target

// Comando adicional por fase (distribuído equilibradamente)
P_cmd_per_phase := P_cmd_in / 3.0;

// Limite de exportação por fase
// Se MaxExportLimit = -90 kW, então por fase = -30 kW
P_phase_limit := -ABS(GVL_Main.MaxExportLimit) / 3.0;

// ════════════════════════════════════════════════════════════════
// ════════════════════════════════════════════════════════════════
// Inicialização
// ════════════════════════════════════════════════════════════════
NO_LIMIT := GVL_Main.InstalledPower * 10.0;  // Valor grande, mas realista
sLimited_phase := '';
bLimitA := FALSE;
bLimitB := FALSE;
bLimitC := FALSE;

// ════════════════════════════════════════════════════════════════
// Se PowerMode = 0, não verifica fase
// ════════════════════════════════════════════════════════════════
IF PowerMode = 0 THEN
    P_cmd_out := P_cmd_in;
    bPhase_limited := FALSE;
    RETURN;
END_IF

// ════════════════════════════════════════════════════════════════
// Proteção: Se InstalledPower não configurado
// ════════════════════════════════════════════════════════════════
IF GVL_Main.InstalledPower <= 0.0 THEN
    P_cmd_out := 0.0;
    bPhase_limited := TRUE;
    sLimited_phase := 'ERROR: InstalledPower=0';
    RETURN;
END_IF

// ════════════════════════════════════════════════════════════════
// Calcula P futuro em cada fase após aplicar comando
// ════════════════════════════════════════════════════════════════
P_future_A := GVL_Main.Pa + P_cmd_per_phase;
P_future_B := GVL_Main.Pb + P_cmd_per_phase;
P_future_C := GVL_Main.Pc + P_cmd_per_phase;

// ════════════════════════════════════════════════════════════════
// Verifica FASE A
// ════════════════════════════════════════════════════════════════
IF P_future_A < 0.0 THEN
    // Fase A estará EXPORTANDO após aplicar comando
    
    IF P_future_A < P_phase_limit THEN
        // Excederia o limite de exportação!
        // Calcula quanto PODE aumentar exportação sem exceder:
        // P_max_per_phase = P_limit - P_atual
        // P_max_total = P_max_per_phase * 3
        P_max_cmd_A := (P_phase_limit - GVL_Main.Pa) * 3.0;
        bLimitA := TRUE;
    ELSE
        // Dentro do limite: sem restrição
        P_max_cmd_A := NO_LIMIT;
    END_IF
    
ELSE
    // Fase A estará IMPORTANDO: sem problema
    P_max_cmd_A := NO_LIMIT;
END_IF

// ════════════════════════════════════════════════════════════════
// Verifica FASE B
// ════════════════════════════════════════════════════════════════
IF P_future_B < 0.0 THEN
    // Fase B estará EXPORTANDO
    
    IF P_future_B < P_phase_limit THEN
        P_max_cmd_B := (P_phase_limit - GVL_Main.Pb) * 3.0;
        bLimitB := TRUE;
    ELSE
        P_max_cmd_B := NO_LIMIT;
    END_IF
    
ELSE
    // Fase B estará IMPORTANDO
    P_max_cmd_B := NO_LIMIT;
END_IF

// ════════════════════════════════════════════════════════════════
// Verifica FASE C
// ════════════════════════════════════════════════════════════════
IF P_future_C < 0.0 THEN
    // Fase C estará EXPORTANDO
    
    IF P_future_C < P_phase_limit THEN
        P_max_cmd_C := (P_phase_limit - GVL_Main.Pc) * 3.0;
        bLimitC := TRUE;
    ELSE
        P_max_cmd_C := NO_LIMIT;
    END_IF
    
ELSE
    // Fase C estará IMPORTANDO
    P_max_cmd_C := NO_LIMIT;
END_IF

// ════════════════════════════════════════════════════════════════
// Aplica o MENOR limite (fase mais restritiva)
// ════════════════════════════════════════════════════════════════
P_max_cmd_total := MIN(P_max_cmd_A, MIN(P_max_cmd_B, P_max_cmd_C));

// ════════════════════════════════════════════════════════════════
// Verifica se houve limitação
// ════════════════════════════════════════════════════════════════
IF P_cmd_in > P_max_cmd_total THEN
    P_cmd_out := P_max_cmd_total;
    bPhase_limited := TRUE;
    
    // Identifica qual(is) fase(s) limitou
    IF bLimitA THEN sLimited_phase := CONCAT(sLimited_phase, 'A'); END_IF
    IF bLimitB THEN sLimited_phase := CONCAT(sLimited_phase, 'B'); END_IF
    IF bLimitC THEN sLimited_phase := CONCAT(sLimited_phase, 'C'); END_IF
    
ELSE
    P_cmd_out := P_cmd_in;
    bPhase_limited := FALSE;
    sLimited_phase := '';
END_IF

P_total_calc := 0.0;

FOR i := 1 TO GVL_Main.NMAXINVERSORES DO     
    
    IF GVL_Persis.InvActivePower[i] > 0.0 THEN
        
        // Proporção do inversor
        proportion := GVL_Persis.InvActivePower[i] / GVL_Main.InstalledPower;
        
        // P proporcional
        P_target_i := P_total_cmd_kW * proportion;
        
        // Limita apenas pela nominal (ignora S_max por enquanto)
        P_actual_i := MIN(P_target_i, GVL_Persis.InvActivePower[i]);
        
        // Armazena P
        GVL_Main.P_inv_kW[i] := P_actual_i;
        
        // Setpoint percentual
        IF GVL_Persis.InvActivePower[i] > 0.0 THEN
            GVL_Main.P_inv_Percent[i] := (P_actual_i / GVL_Persis.InvActivePower[i]) * 100.0;
        ELSE
            GVL_Main.P_inv_Percent[i] := 0.0;
        END_IF
        
        P_total_calc := P_total_calc + P_actual_i;
        
    ELSE
        GVL_Main.P_inv_kW[i] := 0.0;
        GVL_Main.P_inv_Percent[i] := 0.0;
    END_IF
    
END_FOR

// ✅ ATUALIZA SAÍDA
P_allocated_kW := P_total_calc;

// ════════════════════════════════════════════════════════════════
// Reset explícito
// ════════════════════════════════════════════════════════════════
IF bReset THEN
    integ := 0.0;
    LastOut := 0.0;
    u := 0.0;
    bSaturated := FALSE;
    primeiro_ciclo := TRUE;
    RETURN;
END_IF

// ════════════════════════════════════════════════════════════════
// Inicialização suave na primeira execução
// ════════════════════════════════════════════════════════════════
IF primeiro_ciclo THEN
    integ := 0.0;
    primeiro_ciclo := FALSE;
    
    // Se quiser inicializar LastOut com valor atual do medidor:
    // LastOut := feedback;  // Opcional: evita salto inicial
END_IF

// ════════════════════════════════════════════════════════════════
// Cálculo do Erro + Deadband
// ════════════════════════════════════════════════════════════════
erroAtual := setpoint - feedback;

// ✅ Deadband
IF ABS(erroAtual) < Deadband THEN
    erroAtual := 0.0;
END_IF

erro := erroAtual;  // Saída para diagnóstico

// ════════════════════════════════════════════════════════════════
// Componente Proporcional
// ════════════════════════════════════════════════════════════════
u_prop := Kp * erroAtual;

// ════════════════════════════════════════════════════════════════
// Saída Raw (P + I + LastOut)
// ══════════════════════════════════════════���═════════════════════
u_prop := Kp * erroAtual;
u_raw := u_prop + integ;

// ════════════════════════════════════════════════════════════════
// Saturação
// ════════════════════════════════════════════════════════════════
IF u_raw > OutMax THEN
    u_limited := OutMax;
    bSaturated := TRUE;
    sinal_saturacao := 1;
ELSIF u_raw < OutMin THEN
    u_limited := OutMin;
    bSaturated := TRUE;
    sinal_saturacao := -1;
ELSE
    u_limited := u_raw;
    bSaturated := FALSE;
    sinal_saturacao := 0;
END_IF

// ════════════════════════════════════════���═══════════════════════
// Rate Limiter (Rampa)
// ════════════════════════════════════════════════════════════════
delta := u_limited - LastOut;

IF delta > 0.0 THEN
    delta_max := RampUp * CycleTime;
    IF delta > delta_max THEN
        u := LastOut + delta_max;
    ELSE
        u := u_limited;
    END_IF
ELSIF delta < 0.0 THEN
    delta_max := RampDown * CycleTime;
    IF ABS(delta) > delta_max THEN
        u := LastOut - delta_max;
    ELSE
        u := u_limited;
    END_IF
ELSE
    u := u_limited;
END_IF
// ════════════════════════════════════════════════════════════════
// Anti-windup Melhorado (Conditional Integration)
// ════════════════════════════════════════════════════════════════
// Regras:
// 1. NÃO saturado → acumula normALARMente
// 2. Saturado MAS erro na direção oposta → permite desacumular
// 3. Saturado E erro na mesma direção → freeze (não acumula)

IF NOT bSaturated THEN
    // Caso 1: Normal - acumula integral
    integ := integ + (Ki * erroAtual * CycleTime);
    
ELSIF (sinal_saturacao = 1 AND erroAtual < 0.0) OR (sinal_saturacao = -1 AND erroAtual > 0.0) THEN
    // Caso 2: Saturado MAS erro está tentando sair da saturação
    // Permite acumular para ajudar a desaturar
    integ := integ + (Ki * erroAtual * CycleTime);
    
ELSE
    // Caso 3: Saturado E erro empurrando mais para saturação
    // NÃO acumula (freeze integral)
    // integ permanece inalterado
END_IF

// ════════════════════════════════════════════════════════════════
// Atualiza LastOut
// ════════════════════════════════════════════════════════════════
LastOut := u;

// ════════════════════════════════════════════════════════════════
// 1. RESET
// ════════════════════════════════════════════════════════════════
IF Reset THEN
    integral := 0.0;
    MV := 0.0;
    MV_prev := 0.0;
    Error := 0.0;  
    Saturated := FALSE;
    RETURN;
END_IF

// ════════════════════════════════════════════════════════════════
// 2. CALCULA ERRO COM LÓGICA ESPECIAL (PF ≥ TARGET)
// ════════════════════════════════════════════════════════════════

IF PV >= SP THEN
    erro := 0.0;  // PF medido ≥ PF target: objetivo atingido
ELSE
    erro := SP - PV;  // PF medido < PF target: precisa corrigir
END_IF

Error := erro;  // ✅ Saída do erro

// ════════════════════════════════════════════════════════════════
// 3. ZONA MORTA (DEADBAND)
// ════════════════════════════════════════════════════════════════

IF ABS(erro) < DeadbandAbs THEN
    erro := 0.0;
END_IF

// ════════════════════════════════════════════════════════════════
// 4. CÁLCULO PI
// ════════════════════════════════════════════════════════════════

P_term := Kp * erro;
I_term := integral + (Ki * erro * CycleTime);
MV_raw := P_term + I_term;

// ════════════════════════════════════════════════════════════════
// 5. ✅ SATURAÇÃO COM OutMax/OutMin (ALTERAÇÃO)
// ════════════════════════════════════════════════════════════════
IF MV_raw > OutMax THEN
    MV_raw := OutMax;
    sinal_saturacao := 1;
ELSIF MV_raw < OutMin THEN
    MV_raw := OutMin;
    sinal_saturacao := -1;
ELSE
    sinal_saturacao := 0;
END_IF

// ════════════════════════════════════════════════════════════════
// 6. ANTI-WINDUP (Conditional Integration)
// ════════════════════════════════════════════════════════════════

IF bExternal_Saturated OR (sinal_saturacao <> 0) THEN
    // Saturado: só acumula se erro empurra para FORA da saturação
    IF (sinal_saturacao = 1 AND erro < 0.0) OR
       (sinal_saturacao = -1 AND erro > 0.0) THEN
        integral := I_term;  // Permite desacumular
    END_IF
    // Caso contrário: integral permanece (freeze)
    Saturated := TRUE;
ELSE
    integral := I_term;
    Saturated := FALSE;
END_IF

// ════════════════════════════════════════════════════════════════
// 7. RATE LIMITER (Rampa)
// ════════════════════════════════════════════════════════════════

delta := MV_raw - MV_prev;

IF delta > 0.0 THEN
    delta_max := RampUp * GVL_Main.ControlCycle;
    IF delta > delta_max THEN
        MV := MV_prev + delta_max;
    ELSE
        MV := MV_raw;
    END_IF
    
ELSIF delta < 0.0 THEN
    delta_max := RampDown * GVL_Main.ControlCycle;
    IF ABS(delta) > delta_max THEN
        MV := MV_prev - delta_max;
    ELSE
        MV := MV_raw;
    END_IF
    
ELSE
    MV := MV_raw;
END_IF

MV_prev := MV;

// ────────────────────────────────────────────────────────────────
// ETAPA 1: CONTROLADOR PI
// ────────────────────────────────────────────────────────────────

// Setpoint negativo (exportação)
P_setpoint := -ABS(ExportLimit_kW);

// Erro (kW)
P_error_kW := Feedback_kW - P_setpoint;

// Converte deadband (%) para kW (mínimo 1 kW)
// Recalcula apenas se InstalledPower mudou
IF lastInstalledPower <> GVL_Main.InstalledPower THEN
    Deadband_P_kW := MAX(1.0, GVL_Main.InstalledPower * (GVL_Persis.Deadband_P / 100.0));
    Droop_Deadband_kW := MAX(1.0, GVL_Main.InstalledPower * (GVL_Persis.Deadband_Droop / 100.0));
	Deadband_P_kW := MIN(20.0, MAX(1.0, GVL_Main.InstalledPower * (GVL_Persis.Deadband_P / 100.0)));
	Droop_Deadband_kW := MIN(20.0, MAX(1.0, GVL_Main.InstalledPower * (GVL_Persis.Deadband_Droop / 100.0)));		
    lastInstalledPower := GVL_Main.InstalledPower;
END_IF

// Limite máximo do droop (fração da potência instalada)
P_droop_max_kW := GVL_Persis.Droop_Max * GVL_Main.InstalledPower;

// Calcula droop
fbDroop(
    Enable      := GVL_Persis.Droop_Enable,
    bReset      := bReset,                 
    Error_kW    := P_error_kW,
    K_droop     := GVL_Persis.K_Droop,
    Deadband_kW := Droop_Deadband_kW,
    P_max_kW    := P_droop_max_kW
);

P_droop_kW := fbDroop.P_droop_kW;

// PI de potência ativa
fbPI(
    setpoint    := P_error_kW,
    feedback    := 0.0,
    Kp          := GVL_Persis.Kp_P,
    Ki          := GVL_Persis.Ki_P,
    OutMax      := GVL_Main.InstalledPower,
    OutMin      := 0.0,
    CycleTime   := GVL_Main.ControlCycle,
	RampUp      := GVL_Persis.RampUp_P,     
    RampDown    := GVL_Persis.RampDown_P,    
    Deadband    := Deadband_P_kW,
	bReset      := bReset          
);

// Soma droop + PI
P_cmd_sum := P_droop_kW + fbPI.u;

// Comando bruto (segue fluxo normal)
P_cmd_raw := P_cmd_sum;
IF P_cmd_raw < 0.0 THEN
    P_cmd_raw := 0.0;
ELSIF P_cmd_raw > GVL_Main.InstalledPower THEN
    P_cmd_raw := GVL_Main.InstalledPower;
END_IF
bSaturated := fbPI.bSaturated;

// ─────────────────────────────────────────���──────────────────────
// ETAPA 2: SAFETY MARGIN
// ────────────────────────────────────────────────────────────────

fbSafetyMargin(
    P_cmd_raw_kW := P_cmd_raw,
    Margin_pct := GVL_Persis.SafetyMargin_pct,
    TC_Power_kW := GVL_Persis.TC_Power_kW
);

P_cmd_with_margin := fbSafetyMargin.P_cmd_adjusted_kW;
Margin_applied_kW := fbSafetyMargin.Margin_applied_kW;  // ✅ Telemetria
EffectiveExportLimit_kW := P_setpoint + Margin_applied_kW;
// ────────────────────────────────────────────────────────────────
// ETAPA 3: LIMITADOR DE FASE
// ────────────────────────────────────────────────────────────────

fbFLimiter(
    P_cmd_in := P_cmd_with_margin,
    PowerMode := GVL_Persis.PowerMode
);

P_cmd_kW := fbFLimiter.P_cmd_out;
bPhase_limited := fbFLimiter.bPhase_limited;
sLimited_phase := fbFLimiter.sLimited_phase;

// ────────────────────────────────────────────────────────────────
// PROTEÇÃO FINAL: Potência Instalada
// ────────────────────────────────────────────────────────────────

IF P_cmd_kW > GVL_Main.InstalledPower THEN
    P_cmd_kW := GVL_Main.InstalledPower;
    bSaturated := TRUE;
END_IF

(*
    ════════════════════════════════════════════════════════════════
    FB_PowerController - Controlador de Potência Ativa
    ════════════════════════════════════════════════════════════════
    
    Responsabilidade:
    - Calcular comando de P (PI + Safety Margin + Limites de Fase)
    - Encapsular toda lógica relacionada a potência ativa
    
    Pipeline:
    1. PI → P_cmd_raw
    2. Safety Margin → P_cmd_with_margin
    3. Limitador de Fase → P_cmd_limited
    
    ════════════════════════════════════════════════════════════════
*)
FUNCTION_BLOCK FB_PowerController
VAR_INPUT
    ExportLimit_kW : REAL;      // Do scheduler (kW)
    Feedback_kW : REAL;         // Leitura do medidor (kW)
    bReset : BOOL;              // Reset do PI
END_VAR

VAR_OUTPUT
    P_cmd_kW : REAL;            // Comando final (kW)
    bSaturated : BOOL;          // PI saturado
    bPhase_limited : BOOL;      // Limitado por fase
    sLimited_phase : STRING;    // Qual fase limitou
    Margin_applied_kW : REAL;   // Margem aplicada (telemetria)
	EffectiveExportLimit_kW : REAL;
END_VAR

VAR
    // Sub-blocos
    fbPI : FB_PI;
    fbSafetyMargin : FB_SafetyMargin;
    fbFLimiter : FB_FLimiter;
	fbDroop : FB_DroopP;
    
    // Variáveis internas
    P_setpoint : REAL;
    P_cmd_raw : REAL;
    P_cmd_with_margin : REAL;
	lastInstalledPower : REAL := -1.0;
	
	// Droop
    P_error_kW : REAL;
    P_droop_kW : REAL;
	
    P_droop_max_kW : REAL;
    P_cmd_sum : REAL;
	
	// ✅ Deadband em kW (convertido de %)
	Deadband_P_kW     : REAL;
    Droop_Deadband_kW : REAL;
END_VAR

// ════════════════════════════════════════════════════════════════
// INICIALIZAÇÃO
// ════════════════════════════════════════════════════════════════

Q_total := 0.0;
P_total := 0.0;
Q_capacity_total_internal := 0.0;
S_total_used_internal := 0.0;
bQ_limit_reached := FALSE;

// ════════════════════════════════════════════════════════════════
// LOOP PRINCIPAL
// ════════════════════════════════════════════════════════════════

FOR i := 1 TO GVL_Main.NMAXINVERSORES DO
    
    IF GVL_Persis.InvActivePower[i] > 0.0 THEN
        
        // ────────────────────────────────────────────────────────
        // A. LÊ P JÁ ALOCADO
        // ────────────────────────────────────────────────────────
        P_actual_i := GVL_Main.P_inv_kW[i];
        
        // ────────────────────────────────────────────────────────
        // B. CALCULA Q MÁXIMO DISPONÍVEL
        // ────────────────────────────────────────────────────────
        S_available_i := GVL_Persis.InvSmaxPower[i];
        
        IF S_available_i > ABS(P_actual_i) THEN
            Q_max_i := SQRT((S_available_i * S_available_i) - (P_actual_i * P_actual_i));
        ELSE
            Q_max_i := 0.0;
        END_IF
        
        GVL_Main.Inv_Q_available[i] := Q_max_i;
        
        // ─────────────────────────────────────────���──────────────
        // C. DISTRIBUI Q PROPORCIONALARMENTE
        // ────────────────────────────────────────────────────────
        IF GVL_Main.P_allocated_kW > 0.01 THEN
            proportion := GVL_Main.P_inv_kW[i] / GVL_Main.P_allocated_kW;
        ELSE
            proportion := 0.0;
        END_IF
        
        Q_target_i := Q_total_cmd_kvar * proportion;
        
        // ────────────────────────────────────────────────────────
        // D. LIMITA Q AO DISPONÍVEL
        // ────────────────────────────────────────────────────────
        IF ABS(Q_target_i) > Q_max_i THEN
            
            IF Q_target_i >= 0.0 THEN
                Q_actual_i := Q_max_i;
            ELSE
                Q_actual_i := -Q_max_i;
            END_IF
            
            bQ_limit_reached := TRUE;
            GVL_Main.Inv_limited[i] := TRUE;
            
        ELSE
            Q_actual_i := Q_target_i;
            GVL_Main.Inv_limited[i] := FALSE;
        END_IF
        
        // ────────────────────────────────────────────────────────
        // E. ARMAZENA Q
        // ────────────────────���───────────────────────────────────
        GVL_Main.Q_inv_kvar[i] := Q_actual_i;
        
        // ────────────────────────────────────────────────────────
        // F. CALCULA S UTILIZADO (✅ UMA VEZ)
        // ────────────────────────────────────────────────────────
        S_i := SQRT((P_actual_i * P_actual_i) + (Q_actual_i * Q_actual_i));
        
        S_total_used_internal := S_total_used_internal + S_i;
        
        // Utilização de S (%)
        IF S_available_i > 0.0 THEN
            GVL_Main.Inv_S_utilization[i] := (S_i / S_available_i) * 100.0;
        ELSE
            GVL_Main.Inv_S_utilization[i] := 0.0;
        END_IF
        
        // ────────────────────────────────────────────────────────
        // G. CALCULA PF INDIVIDUAL
        // ────────────────────────────────────────────────────────
        IF S_i > 0.01 THEN
            GVL_Main.PF_inv[i] := P_actual_i / S_i;
        ELSE
            GVL_Main.PF_inv[i] := 1.0;
        END_IF
        
        // ────────────────────────────────────────────────────────
        // H. ACUMULADORES
        // ────────────────────────────────────────────────────────
        P_total := P_total + P_actual_i;
        Q_total := Q_total + Q_actual_i;
        Q_capacity_total_internal := Q_capacity_total_internal + Q_max_i;
        
    ELSE
        // Inversor inativo
        GVL_Main.Q_inv_kvar[i] := 0.0;
        GVL_Main.PF_inv[i] := 1.0;
        GVL_Main.Inv_Q_available[i] := 0.0;
        GVL_Main.Inv_S_utilization[i] := 0.0;
        GVL_Main.Inv_limited[i] := FALSE;
    END_IF
    
END_FOR

// ════════════════════════════════════════════════════════════════
// SAÍDAS
// ════════════════════════════════════════════════════════════════

Q_allocated_kvar := Q_total;
Q_capacity_total := Q_capacity_total_internal;
S_total_used := S_total_used_internal;

// PF efetivo total
IF P_total > 0.01 OR ABS(Q_total) > 0.01 THEN
    S_total := SQRT((P_total * P_total) + (Q_total * Q_total));
    PF_effective := P_total / S_total;
ELSE
    PF_effective := 1.0;
END_IF

(*
    ════════════════════════════════════════════════════════════════
    FB_QAlloc - Alocador de Potência Reativa
    ════════════════════════════════════════════════════════════════
*)

FUNCTION_BLOCK FB_QAlloc
VAR_INPUT
    Q_total_cmd_kvar : REAL;        // Comando de Q total (do FB_PIQ)
END_VAR

VAR_OUTPUT
    bQ_limit_reached : BOOL;        // TRUE = Não conseguiu alocar todo Q
    Q_allocated_kvar : REAL;        // Q efetivamente alocado
    PF_effective : REAL;            // PF efetivo total resultante
    Q_capacity_total : REAL;        // Capacidade total de Q disponível (kvar)
    S_total_used : REAL;            // S total utilizado (kVA)
END_VAR

VAR

	// ✅ Acumuladores totais
    Q_total : REAL;
    P_total : REAL;
    Q_capacity_total_internal : REAL;
    S_total_used_internal : REAL;

	// ✅ Variáveis por inversor
    Q_target_i : REAL;
    Q_actual_i : REAL;
    Q_max_i : REAL;
    S_available_i : REAL;
    P_actual_i : REAL;
	
    // ✅ Auxiliares
    i : UINT;
    proportion : REAL;
    S_total : REAL;
    S_i : REAL;  // ✅ S do inversor i (calculado 1 vez)
END_VAR

// ════════════════════════════════════════════════════════════════
// IMPLEMENTAÇÃO
// ════════════════════════════════════════════════════════════════
// 1. Proteção: se TC não configurado, não aplica margem
IF TC_Power_kW <= 0.0 THEN
    P_cmd_adjusted_kW := P_cmd_raw_kW;
    Margin_applied_kW := 0.0;
    RETURN;
END_IF

// 2. Calcula margem em kW
SafetyMargin_kW := (Margin_pct / 100.0) * TC_Power_kW;

// 3. Aplica margem (reduz comando)
P_cmd_adjusted_kW := P_cmd_raw_kW - SafetyMargin_kW;

// 4. Limita para não ficar negativo
IF P_cmd_adjusted_kW < 0.0 THEN
    P_cmd_adjusted_kW := 0.0;
END_IF

// 5. Armazena margem aplicada (para HMI)
Margin_applied_kW := SafetyMargin_kW;

// ════════════════════════════════════════════════════════════════
// 1. LEITURA DO RELÓGIO DO SISTEMA (UTC)
// ════════════════════════════════════════════════════════════════

GVL_Main.timestampUTC := TO_UDINT(SysTimeRtcGet(GVL_Main.Result));

GVL_ALARM_MANAGER.CRIT_RTC_FAIL:=(GVL_Main.Result <> eResultCode.OK);
IF GVL_ALARM_MANAGER.CRIT_RTC_FAIL THEN
    // ❌ ERRO: Relógio não disponível
    GVL_Main.MaxExportLimit := 0.0;
	FC_LogEvent(
		eCode:=E_EventCode.CRIT_RTC_FAILED,
		bRaised:=TRUE,
		rParam1:=0.0,
		rParam2:=0.0,
		uMachState := GVL_Main.uMachineState
		);
    RETURN;
END_IF

// ════════════════════════════════════════════════════════════════
// 2. CÁLCULO DO OFFSET TOTAL (Fuso + Horário de Verão)
// ════════════════════════════════════════════════════════════════

// Offset base (fuso horário em segundos)
offsetSeconds := GVL_Main.TIMEZONEOFFSET * 3600;  // Ex: -3 * 3600 = -10800

// Adiciona horário de verão se ativo
IF GVL_Persis.bHorarioVerao THEN
    offsetSeconds := offsetSeconds + 3600;      // +1 hora
END_IF

// ════════════════════════════════════════════════════════════════
// 3. APLICA OFFSET AO TIMESTAMP UTC
// ════════════════════════════════════════════════════════════════

// ✅ MÉTODO SEGURO: Usa valor absoluto e subtrai/soma conforme sinal
offsetSeconds_ABS := DINT_TO_UDINT(ABS(offsetSeconds));

IF offsetSeconds < 0 THEN
    // Fuso NEGATIVO (Américas): subtrai
    timestampLocal_UDINT := GVL_Main.timestampUTC - offsetSeconds_ABS;
ELSE
    // Fuso POSITIVO (Europa, Ásia): soma
    timestampLocal_UDINT := GVL_Main.timestampUTC + offsetSeconds_ABS;
END_IF

// ════════════════════════════════════════════════════════════════
// 4. CONVERTE TIMESTAMP PARA DATA/HORA LOCAL
// ════════════════════════════════════════════════════════════════

dtNowLocal := UDINT_TO_DT(timestampLocal_UDINT);
dataNowLocal := TO_DATE(dtNowLocal);

// Extrai hora (0..23)
todNowLocal := DT_TO_TOD(dtNowLocal);
todAsDword := TOD_TO_DWORD(todNowLocal);
hora := DWORD_TO_INT(todAsDword / DWORD#3600000);

// Extrai dia da semana (1=Dom .. 7=Sáb)
diadasemana := UDINT_TO_INT(((timestampLocal_UDINT / 86400) + 4) MOD 7) + 1;

// ════════════════════════════���═══════════════════════════════════
// 5. VERIFICA MUDANÇA DE DATA (Para atualizar cache)
// ════════════════════════════════════════════════════════════════

IF dataNowLocal <> lastCheckedDate THEN
    
    lastCheckedDate := dataNowLocal;
    cachedSpecialDateLimit := -1.0;  // Invalida cache
    
    FOR i := 1 TO GVL_Main.NDATASESPECIAIS DO
        
        // ✅ OTIMIZAÇÃO: Early exit se encontrar data vazia
        IF GVL_Persis.DatasEspeciais[i] = DATE#1970-01-01 THEN
            EXIT;  // Resto do array está vazio
        END_IF
        
        // Verifica se é data especial
        IF GVL_Persis.DatasEspeciais[i] = dataNowLocal THEN
            cachedSpecialDateLimit := GVL_Persis.SpecialDaySchedule[i];
            EXIT;  // Encontrou, pára a busca
        END_IF
        
    END_FOR
    
END_IF

// ════════════════════════════════════════════════════════════════
// 6. USA CACHE DE DATA ESPECIAL (Se válido)
// ════════════════════════════════════════════════════════════════

IF cachedSpecialDateLimit >= 0.0 THEN
    // Data especial ativa
    GVL_Main.MaxExportLimit := cachedSpecialDateLimit;
	FC_LogEvent(
		eCode:=E_EventCode.INFO_SPECIAL_DATE_ACTIVE,
		bRaised:=TRUE,
		rParam1:=0.0,
		rParam2:=0.0,
		uMachState := GVL_Main.uMachineState
		);
    RETURN;																				// se é data especial, não olha busca por dia e hora, aborta
END_IF

// ════════════════════════════════════════════════════════════════
// 7. AGENDA SEMANAL (Hora Local)
// ════════════════════════════════════════════════════════════════

// ✅ VALIDAÇÃO: Verifica se índices estão dentro dos limites
semanaindex:= (diadasemana >= 1 AND diadasemana <= 7) AND (hora >= 0 AND hora <= 23);
GVL_ALARM_MANAGER.CRIT_SCHEDULE_INDEX_INVALID:= NOT semanaindex;

IF semanaindex THEN
    GVL_Main.MaxExportLimit := GVL_Persis.WeekSchedule_kW[diadasemana, hora + 1];     // Acessa agenda semanal
ELSE																				  // ❌ ERRO: Índice inválido (não deveria ocorrer)
    GVL_Main.MaxExportLimit := 0.0;
	FC_LogEvent(
		eCode:=E_EventCode.CRIT_SCHEDULE_INDEX_INVALID,
		bRaised:=TRUE,
		rParam1:=0.0,
		rParam2:=0.0,
		uMachState := GVL_Main.uMachineState
		);
    
END_IF

(*
    FB_Scheduler
    - Agenda semanal: 24 intervalos por dia, 7 dias.
    - Recebe Hora UTC do sistema e converte internamente para LOCAL (Fuso + DST).
    - Feriados/datas especiais sobrescrevem a agenda.
    - Saída: setpoint % da potência instalada.
*)
FUNCTION_BLOCK FB_Scheduler

VAR
    // ════════════════════════════════════════════════════════════
    // VARIÁVEIS DE TIMESTAMP
    // ════════════════════════════════════════════════════════════
    timestampLocal_UDINT : UDINT;           // ✅ Apenas UDINT (sem DINT)
    offsetSeconds : DINT;                   // Offset em segundos (pode ser negativo)
    offsetSeconds_ABS : UDINT;              // Valor absoluto do offset
    
    // ════════════════════════════════════════════════════════════
    // CONVERSÕES DE DATA/HORA
    // ════════════════════════════════════════════════════════════
    dtNowLocal : DATE_AND_TIME;
    dataNowLocal : DATE;
    todNowLocal : TOD;
    todAsDword : DWORD;
    hora : INT;
    diadasemana : INT;
	semanaindex : BOOL;
    
    // ════════════════════════════════════════════════════════════
    // CACHE DE DATAS ESPECIAIS (Otimização)
    // ════════════════════════════════════════════════════════════
    lastCheckedDate : DATE := DATE#1970-01-01;      // Última data verificada
    cachedSpecialDateLimit : REAL := -1.0;          // -1 = inválido
    
    // ════════════════════════════════════════════════════════════
    // AUXILIARES
    // ════════════════════════════════════════════════════════════
    i : UINT;
END_VAR

{attribute 'qualified_only'} VAR_GLOBAL // ───────────────────────────────────────────────────────── // ALARM MANAGER FLAGS (condições booleanas) // ─────────────────────────────────────────────────────────
// Falhas na inicialização CRIT_SERIAL_INIT_FAIL : BOOL := FALSE; // Critico - Falha para iniciar as seriais CRIT_K1_TIMEOUT : BOOL := FALSE; // Critico - falha no acionamento de K1 CRIT_K2_TIMEOUT : BOOL := FALSE; // Critico - falha no acionamento de K2
// Medição / Medidor ALARM_MEAS_MODBUS_TIMEOUT : BOOL := FALSE; // timeout de leitura (READ) ALARM_MEAS_MODBUS_ERRO : BOOL := FALSE; // xError do medidor (READ) ALARM_MEAS_FROZEN : BOOL := FALSE; // diagnosticCode = A900 (se aplicável) ALARM_MEAS_USING_LAST_VALUEU : BOOL := FALSE; // bPoucosErros=TRUE e bDadosOK=FALSE ALARM_MEAS_RANGE_ERROR : BOOL := FALSE; // Warning: Valor fora de faixa ALARM_MEAS_XCHECK_FAIL : BOOL := FALSE; // Warning: Validação cruzada CRIT_MEAS_PERSISTENT_FAIL : BOOL := FALSE; // bPoucosErros = FALSE CRIT_MEAS_MODBUS_TIMEOUT : BOOL := FALSE; // timeout de leitura (READ) repeticao fora da tolerancia CRIT_MEAS_MODBUS_ERRO : BOOL := FALSE; // xError do medidor (READ) repeticao fora da tolerancia
// Comunicação inversores CRIT_COM_CHANNEL_FAIL : BOOL := FALSE; // falha geral de comunicação → FAIL/STOP CRIT_CH1_MODBUS_TIMEOUT : BOOL := FALSE; // Canal COM1 TIMEOUT 3x CRIT_CH2_MODBUS_TIMEOUT : BOOL := FALSE; // Canal COM2 TIMEOUT 3x CRIT_CH1_MODBUS_ERRO : BOOL := FALSE; // >50% falhas COM1 no ciclo CRIT_CH2_MODBUS_ERRO : BOOL := FALSE; // >50% falhas COM2 no ciclo
// Sistema ALARM_SCAN_OVERRUN : BOOL := FALSE; // Warning: Watchdog de ciclo ALARM_TC_POWER_NOT_SET : BOOL := FALSE; // TC_Power_kW = 0 na inicialização CRIT_NO_INVERTERS : BOOL := FALSE; // Error: Nenhum inversor configurado CRIT_RTC_FAIL : BOOL := FALSE; // Error: Falha RTC CRIT_INSTALLED_PWR_ZERO : BOOL := FALSE; // Error: Potência instalada = 0 CRIT_INSTALLED_SMAX_ZERO : BOOL := FALSE; // Error: Potência reativa instalada = 0 CRIT_SCAN_OVERRUN : BOOL := FALSE; // CRITICO: Watchdog de ciclo 3x
// Proteções normativas CRIT_HARDLIMIT_15S : BOOL := FALSE; // Error: P > LPI+10% por >15s CRIT_EXPORT_OVER_LPI_30S : BOOL := FALSE; // Error: P > LPI por >30s CRIT_K2_NOT_OPENED : BOOL := FALSE; // Error: K2 não abriu após trip
// Status do sistema ALARM_FAIL_ACTIVE : BOOL := FALSE; // MachineState=FAIL CRIT_STOP_ACTIVE : BOOL := FALSE; // MachineState=STOP CRIT_SCHEDULE_INDEX_INVALID : BOOL := FALSE; // Dia ou hora da semana inválido (CRITICAL)
// ── Controle / PF ── ALARM_PF_BELOW_TARGET : BOOL := FALSE; // Warning: PF < 0.92 ALARM_PF_CRITICAL : BOOL := FALSE; // Error: PF < 0.92 + Q saturado ALARM_Q_LIMITED_BY_SMAX : BOOL := FALSE; // Info: Q limitado por S END_VAR

{attribute 'qualified_only'}
// ════════════════════════════════════════════════════════════════════
// GVL_EventLog — Constantes do sistema de log de eventos
// ════════════════════════════════════════════════════════════════════
// Autor: Eng. Principal / Revisão Técnica PPC-GD
// Plataforma: WAGO CC100 (751-9402) / CODESYS V3.5 SP21 Patch 4
//
// DIMENSIONAMENTO:
//   64 entradas × 28 bytes = ~1.792 bytes de RETAIN
//   WAGO CC100 possui ~32 kB RETAIN → uso < 6%
//   Com ~1 evento/min, cobre >1 hora de histórico completo
//   Com taxa de pico (~10 eventos em cascata), ainda retém >6 min
// ════════════════════════════════════════════════════════════════════
{attribute 'qualified_only'}
VAR_GLOBAL CONSTANT
    MAX_EVENT_ENTRIES   : UINT := 64;   // Tamanho do ring buffer (potência de 2 facilita debug)
END_VAR

{attribute 'qualified_only'}
VAR_GLOBAL CONSTANT

    // Parâmetros do sistema
    SOFTVERSION          		: UINT := 21;   				// Versão da aplicação
	DATAAPLICATION				: DATE := DATE#2025-12-05;		// Data da aplicação
	NMAXINVERSORES				: UINT := 30;					// Capacidade máxima de inversores
	TIPOSINVERSORES				: UINT := 8;					// total de inversores diferentes que podem estar presentes
	NDATASESPECIAIS 			: UINT := 48; 					// Quantidade de datas especiais disponíveis ao todo (para 10 anos)
	TIMEZONEOFFSET				: DINT := -3; 			
    CYCLE_TIME_MS				: UDINT := 1000;  				// tempo de ciclo de controle
	CYCLE_TIME_TOLERANCE		: UDINT := 1100;  				// tolerancia de ultrapassagem para tempo de ciclo de controle de 10%
	MAX_Meas_MODBUS_ERROS		: UDINT := 0;					// quantidade de erros permitido na leitura do medidor
	MAX_Meas_MODBUS_TIMEOUTS	: UDINT := 0;					// quantidade de timeouts permitido na leitura do medidor

	
END_VAR

VAR_GLOBAL
	timestampUTC				: UDINT;
	Result 						: RTS_IEC_RESULT;
  	ControlCycle    			: REAL;            					// Tempo de ciclo de controle em SEGUNDOS (ex: 1.0 = 1 segundo)
	uMachineState				: E_MachineState;
	fbEventLog 					: FB_EventLog;						// Function Block de registro de eventos 
	
	// Quantidade de inversores por canal
	MAX_CH1_MODBUS_ERROS		: UDINT := 0;						// < 50% da quantidade de inversores sem ir para FAIL
	MAX_CH1_MODBUS_TIMEOUTS		: UDINT := 0;						// < 50% da quantidade de inversores sem ir para FAIL
	MAX_CH2_MODBUS_ERROS		: UDINT := 0;						// < 50% da quantidade de inversores sem ir para FAIL
	MAX_CH2_MODBUS_TIMEOUTS		: UDINT := 0;						// < 50% da quantidade de inversores sem ir para FAIL
	NInversoresCOM01    		: UINT :=0;
	NInversoresCOM02    		: UINT :=0;
	
	// Saidas digitais
  	K1_out  					: BOOL;   							// DI X5_1 - K1 - controle permissivo
	K2_out						: BOOL;								// DI X5_2 - K2 - controle trip
  	K3RedOut					: BOOL;								// DI X5_3 - nada pronto - acende vermelho
  	K4YellowOut  				: BOOL;   							// DI X5_4 - K2 aberto - acende amarelo
  	K5GreenOut  				: BOOL;   							// DI X5_5 - K2 fechou - acende verde
	K7OkOut  					: BOOL;   							// DI X5_7 - sinaliza ok
	K8ErroOut  					: BOOL;   							// DI X5_8 - sinaliza erro
		
	// Entredas digitais
	K1_in        				: BOOL;                				// DI X12_1 - contato auxliar de K1
  	K2_in        				: BOOL;                				// DI X12_2 - contato auxliar de K2

    //    Medições (REAL) - Tensões (V), Correntes (A), Potências Ativas (W), Potências Reativas (var), PF (adimensional, sinal: + indutivo, - capacitivo)
	
    Ua  			: REAL := 0.0; // Tensão de fase A   - 2006H - Tensão de fase A em Volts (x 0,1 V)
    Ub  			: REAL := 0.0; // Tensão de fase B   - 2008H - Tensão de fase B em Volts (x 0,1 V)
    Uc  			: REAL := 0.0; // Tensão de fase C   - 200AH - Tensão de fase C em Volts (x 0,1 V)
	
	Ia    			: REAL 	:= 0.0; // 200CH - Corrente de fase A em A (x 0,001 A) 
	Ib    			: REAL 	:= 0.0; // 200EH - Corrente de fase B em A (x 0,001 A) 
	Ic    			: REAL 	:= 0.0; // 2010H - Corrente de fase C em A (x 0,001 A) 
	
	Pt    			: REAL 	:= 0.0; // 2012H - Potencia ativa combinada em kW (x 0.1 para W, x 0.0001 para kW)
	Pa    			: REAL 	:= 0.0; // 2014H - Potencia ativa fase A 	em kW (x 0.1 para W, x 0.0001 para kW)
	Pb    			: REAL 	:= 0.0; // 2016H - Potencia ativa fase B 	em kW (x 0.1 para W, x 0.0001 para kW)
	Pc    			: REAL 	:= 0.0; // 2018H - Potencia ativa fase C    em kW (x 0.1 para W, x 0.0001 para kW)

	Qt    			: REAL 	:= 0.0; // 201AH - Potencia reativa combinada em kvar (x 0.1 para var, x 0.0001 para kvar)
	Qa    			: REAL 	:= 0.0; // 201CH - Potencia reativa fase A	 em kvar (x 0.1 para var, x 0.0001 para kvar)
	Qb    			: REAL 	:= 0.0; // 201EH - Potencia reativa fase B	 em kvar (x 0.1 para var, x 0.0001 para kvar)
	Qc    			: REAL 	:= 0.0; // 2020H - Potencia reativa fase C	 em kvar (x 0.1 para var, x 0.0001 para kvar)
	
	PFt    			: REAL 	:= 0.0; // 202AH - Fator de potência combinado (número positivo: indutivo, número negativo: capacitivo) (x0,001)
	PFa    			: REAL 	:= 0.0; // 202CH - Fator de potência de fase A (número positivo: indutivo, número negativo: capacitivo) (x0,001)
	PFb    			: REAL 	:= 0.0; // 202EH - Fator de potência de fase B (número positivo: indutivo, número negativo: capacitivo) (x0,001)
	PFc    			: REAL 	:= 0.0; // 2030H - Fator de potência de fase C (número positivo: indutivo, número negativo: capacitivo) (x0,001)	

    //   COMANDOS E TELEMETRIA - Saídas do Controle 
	
	// definição dos inversores dos dois canais de comunicação
	
	trigInvCOM100  	: ARRAY[1..15] OF BOOL;
    pInversores100 	: ARRAY [1..15] OF POINTER TO ModbusSlaveComPort; 				// array de pointers para Inversor01..Inversor15 (apenas ponteiros - não recria instâncias)
	trigMedidor100 	: BOOL;
	pMedidor100		: POINTER TO ModbusSlaveComPort;
	
	trigInvCOM200  	: ARRAY[1..15] OF BOOL;
	pInversores200 	: ARRAY [1..15] OF POINTER TO ModbusSlaveComPort; 				// array de pointers para Inversor01..Inversor15 (apenas ponteiros - não recria instâncias)
	trigMedidor200 	: BOOL;
	pMedidor200		: POINTER TO ModbusSlaveComPort;
	
	// Potencia Total instalada e potencia Aparente Total instalada
  	InstalledPower 	: REAL; 														// Soma da potência nominal de todos os inversores ativos
	Q_max_permitido : REAL := 0.0;    												// Q máximo permitido (kvar)
	InstalledSmax   : REAL; 														// NOVO: Potência Aparente Máxima Total (kVA)	
	
	// COMANDOS DE CONTROLE
	MaxExportLimit 	: REAL;              											// Limite de exportação do scheduler (kW)
	P_cmd_total_kW 	: REAL;              											// Comando total de P (kW)
	Q_cmd_total_kvar: REAL;            												// Comando total de Q (kvar)
	
    // Telemetria: Setpoint atual da agenda (antes das proteções)
    TotalPowerPercent : REAL;

    // Telemetria: Potência Reativa total desejada (kVA)
    TotalReactivePower : REAL;

    // Telemetria: Valores efetivos calculados para cada inversor
    P_inv_kW     	: ARRAY[1..NMAXINVERSORES] OF REAL; 							// valor de setpoint de potencia ativa em kW
	P_inv_Percent 	: ARRAY[1..NMAXINVERSORES] OF REAL; 							// valor de setpoint de potencia ativa em percentual do nominal
    Q_inv_kvar    	: ARRAY[1..NMAXINVERSORES] OF REAL; 							// valor de setpoint de potencia reativa em kVA
    PF_inv 			: ARRAY[1..NMAXINVERSORES] OF REAL; 							// valor do fator de potencia de cada inversor (deve ser 0,92 para todos)
	P_inv_limit 	: ARRAY[1..NMAXINVERSORES] OF REAL; 							// valor limite de potencia ativa com base na SMAX de cada um
	
	// Margem de segurança para compensar erro de TC perto de zero, o sistema tentará manter importação mínima garantido que não haja exportação
	SafetyMargin_pct: REAL :=0.03;
	TC_Power_kW		: REAL := 0.0; // deve ser configurado como 3% da potencia total sob controle pelo TC
	
	// ════════════════════════════════════════════════════════════════
	// DIAGNÓSTICO DE PF
	// ════════════════════════════════════════════════════════════════
	Q_available_max : REAL;             											// Q máximo disponível (kvar)
	PF_effective 	: REAL;                											// PF efetivo resultante
	PFErro 			: BOOL;                   										// TRUE = PF < 0.92 não atingível (banco de capacitores)
    
	// ════════════════════════════════════════════════════════════════
    // DIAGNÓSTICO DE FATOR DE POTÊNCIA
    // ════════════════════════════════════════════════════════════════
    
    // Status geral
    PF_target : REAL := 0.92;                   // PF alvo (mínimo aceitável)
    PF_measured : REAL;                         // PF medido no ponto de conexão
    PF_achieved : REAL;                         // PF efetivamente alcançado após compensação
    PF_OK : BOOL;                               // TRUE = PF ≥ 0.92
    
    // Potências
    P_generated_kW : REAL;                      // P total gerado pelos inversores
    P_allocated_kW : REAL;                      // P efetivamente alocado
    Q_measured_kvar : REAL;                     // Q medido no ponto de conexão (carga)
    Q_required_kvar : REAL;                     // Q necessário para atingir PF ≥ 0.92
    Q_commanded_kvar : REAL;                    // Q comandado pelo FB_PIQ
    Q_available_kvar : REAL;                    // Q que inversores conseguem fornecer
    Q_allocated_kvar : REAL;                    // Q efetivamente alocado
    Q_deficit_kvar : REAL;                      // Déficit de Q (se > 0, falta Q)
    
    // Capacidade dos inversores
    S_total_available_kVA : REAL;               // S total disponível (soma de todos inversores)
    S_total_used_kVA : REAL;                    // S total utilizado
    S_utilization_pct : REAL;                   // % de utilização de S
    Q_capacity_total_kvar : REAL;               // Capacidade total de Q dos inversores (atual)
    Q_utilization_pct : REAL;                   // % de utilização de Q
    
    // Diagnóstico e recomendações
    Q_deficit_percent : REAL;                   // Déficit de Q em % do necessário
    Capacitor_bank_size_kvar : REAL;            // Tamanho recomendado de banco de capacitores
    Capacitor_bank_recommended : BOOL;          // TRUE = Recomenda banco de capacitores
    PF_alarm_code : UINT;                       // Código de alarme (0=OK, 1=Aviso, 2=Crítico)
    
    // Histórico (opcional)
    PF_min_24h : REAL := 1.0;                   // PF mínimo nas últimas 24h
    PF_avg_24h : REAL := 1.0;                   // PF médio nas últimas 24h
    Q_deficit_max_24h : REAL;                   // Déficit máximo de Q nas últimas 24h
    PF_alarm_count_24h : UDINT;                 // Quantidade de alarmes nas últimas 24h
    
    // Inversores individuais (diagnóstico detalhado)
    Inv_S_utilization : ARRAY[1..NMAXINVERSORES] OF REAL;  // % S usado por inversor
    Inv_Q_available : ARRAY[1..NMAXINVERSORES] OF REAL;    // Q disponível por inversor (kvar)
    Inv_limited : ARRAY[1..NMAXINVERSORES] OF BOOL;        // TRUE = Inversor limitado por S	
END_VAR

{attribute 'qualified_only'}
VAR_GLOBAL PERSISTENT RETAIN

    // CONFIGURAÇÕES DO SISTEMA (Dados que não podem ser perdidos no desligamento)
    
	// Definição do medidor a ser usado
	MeasDeviceType 		: E_MeasDeviceType := E_MeasDeviceType.CHINT_DTSU666;
    
    // Potência nominal (kW) por tipo
    InvActivePower 		: ARRAY[1..GVL_Main.NMAXINVERSORES] OF REAL; 		// kW
    // Potência Aparente Máxima (kVA) por tipo 
    InvSmaxPower 		: ARRAY[1..GVL_Main.NMAXINVERSORES] OF REAL;		// kVA

    // --- Parâmetros de Controle de Exportação ---
    PowerMode 			: UINT := 2;      								// 0=Total, 1=Por Fase, 2=Ambos
	OperationMode		: BOOL := TRUE;									// FALSE=Export Control  TRUE=Zero Grid
	ControlMode			: UINT := 1;									// 0 = manual  1 = automatico (PI ativo)
    TotALARMaxExport_kW : REAL := 0; 									// Limite físico total (kW)
    PhaseMaxExport_kW 	: REAL := 0; 									// Limite físico por fase (kW)

    (* 
	Regra prática para GD solar: Ti entre 5s e 20s. Mais rápido pode oscilar com a latência Modbus. 
	Mais lento perde capacidade de compensar nuvens passando.
	Ti é o Tempo Integral do controlador PI, também chamado de tempo de reset.
	Relação Ki= Kp / Ti   Então se você tem Kp = 1.0 e Ti = 10s => Ki=1.0/10 = 0.1 (por segundo)
	Na prática para seu sistema:
	Ti pequeno (ex: 2s) → integral age rápido → mais agressivo → risco de oscilação
	Ti grande (ex: 30s) → integral age devagar → mais conservador → lento para corrigir erro estacionário
	Ti = 10s → o controlador elimina o erro estacionário em aproximadamente 30 a 40 segundos (≈ 3-4 × Ti)
	Resumo em uma frase:
	Ti = 10s é "quanto tempo o integrador leva para alcançar a mesma força que o proporcional já deu instantaneamente".
	*)
	
	// --- Controle Droop (Potência Ativa) ---
	Droop_Enable     	: BOOL := TRUE;      							// Habilita droop
	K_Droop          	: REAL := 0.15;      							// kW/kW  (ex.: 0.05 = 5% de ganho)
	Deadband_Droop   	: REAL := 2.0;       							// % (erro menor não gera droop)
	Droop_Max        	: REAL := 0.4;       							// Fração da potência instalada (ex.: 0.6 = 60%)
	
	// --- Parâmetros do Controlador PI (Potência Ativa) ---
    Kp_P           		: REAL := 0.25;									// Recomendado: 0.1 a 1.0
																	    // Maior → resposta mais rápida, risco de oscilação
																	    // Menor → mais suave, mas mais lento
    Ki_P           		: REAL := 0.02;									// Recomendado: 0.02 a 0.1 - Com 1s de ciclo e tempo morto ~1,2–1,6s, integral muito alto oscila.
																		// Com T=1s: constante de tempo integral Ti = Kp/Ki = 12,5s
																	    // Significado: elimina erro estacionário em ~10 segundos
																	    // NUNCA > 0.2 com T=1s (oscilação garantida)
	RampUp_P 			: REAL := 15.0;           						// Rampa de subida (kW/s) - limitar a 15-20 kW/s por causa do sweep de setpoints nos inversores
	RampDown_P 			: REAL := 20.0;         						// Rampa de descida (kW/s) - RampDown_P ≤ 20–30 kW/s
    Deadband_P  		: REAL := 1.0;  								// % da potência instalada (ex: 1.0 = 1%)
	
    // --- Configuração de Fator de Potência (PF) e Reativos (Q) ---
    PF_target       	: REAL := 0.92; 								// Alvo |PF|
	PF_sign				: REAL := 1.0;
    // Parâmetros do PI de Correção de Q (Feedforward + Feedback)
    Kp_Q           		: REAL := 50.0;									// Recomendado: 20.0 a 100.0 kvar/pu_PF
																	    // Unidade: kvar por unidade de erro de PF
																	    // Ex: erro PF = 0.02 → P_term = 50 * 0.02 = 1.0 kvar
    Ki_Q           		: REAL := 5.0;									// Recomendado: 2.0 a 10.0 kvar/(pu_PF·s
																	    // Com T=1s: Ti = Kp/Ki = 10s => elimina erro em ~30-40s
																	    // Significado: corrige PF em ~10 segundos	
	RampUp_Q 			: REAL := 50.0;            						// Rampa de subida (kvar/s)
	RampDown_Q 			: REAL := 50.0;          						// Rampa de descida (kvar/s)
	Deadband_Q 			: REAL := 0.01;          						// Zona morta de PF (ex: 0.01 = ±0.01) — padrão para GD

    // --- Histerese de Habilitação ---
    HysteresisOn	   	: REAL := 0.01; 								// Liga controle acima de 1%
    HysteresisOff		: REAL := 0.01; 								// Desliga abaixo de 1%
		
    // --- Agenda Semanal (7 dias x 24 horas) e Datas Especiais
	bHorarioVerao 		: BOOL:= FALSE;									// se TRUE  = Horário de Verão Ativo (+1h)
    WeekSchedule_kW 	: ARRAY[1..7, 1..24] OF REAL; 					// (1=Dom 2=Seg 3=Ter 4=Quarta 5=Quinta 6=Sexta 7=Sábado) em kW
    DatasEspeciais   	: ARRAY[1..GVL_Main.NDATASESPECIAIS] OF DATE;		// inicializa com zeros
	SpecialDaySchedule 	: ARRAY[1..GVL_Main.NDATASESPECIAIS] OF REAL;		// cada data especial tem apenas um valor de potencia maxima valido para o dia inteiro

    // ════════════════════════════════════════════════════════════════
    // LIMITES FÍSICOS DO SISTEMA (Baseados no Transformador e Rede)
    // ════════════════════════════════════════════════════════════════
	// SafetyMargin_kW = SafetyMargin_pct × TC_Power_kW / 100 - Margem de segurança para compensar erro de TC perto de zero
	SafetyMargin_pct 	: REAL := 3.0;     								// Percentual do TC (%)
	// Exemplo 1: TC de 500 A, Tensão 380 V => P_TC = √3 × V × I = 1.732 × 380 × 500 = 329 kW
	TC_Power_kW			: REAL := 0.0; 									// deve ser configurado como 3% da potencia total sob controle pelo TC
	
	VMIN 				: REAL := 7170;  // Volts - tensão de fase minima para tensão primária de 13,8kV
    VMAX 				: REAL := 8370;  // Volts - tensão de fase máxima para tensão primária de 13,8kV
    IMAX 				: REAL := 125.0;  // Amperes - corrente de linha - para potencia de usina de 3MW erro transformador 5%
    PMAX 				: REAL := 3200.0; // kW (Demanda contratada + 10% de margem)
	QMAX				: REAL := 2400.0; // kvar tan(acos(0.8)) × Pmax
	// τ = tempo para atingir ~63% do valor final e T_scan = período de amostragem (1s no seu caso)
	// α = T_scan / (τ + T_scan)  => Alpha=0.5 => 3 segundos para atingir 95% do valor final
	// Item 2.1: "Responder em até 15 segundos a rejeição de carga"
	// Item 2.2: "Limitar exportação em até 15 segundos"
	// Nuvens passageiras: variação em 1–5 segundos
	// Rejeição de carga: instantânea (< 1s)
	// Ruído de medição: < 100 ms
	ALPHA				: REAL := 0.25;
	
END_VAR

// ════════════════════════════════════════════════════════════════════
// Corpo do FB_EventDisplay — executa quando bRefresh tem borda de subida
// ════════════════════════════════════════════════════════════════════
rTrigRefresh(CLK := bRefresh);

IF rTrigRefresh.Q THEN

    // Total de eventos e páginas
    nTotalEvents := pEventLog.nCount;
    IF nTotalEvents > 0 THEN
        nTotalPages := ((nTotalEvents - 1) / DISPLAY_LINES) + 1;
    ELSE
        nTotalPages := 0;
    END_IF

    // Clamp página
    IF nPageOffset >= nTotalPages THEN
        nPageOffset := 0;
    END_IF
    nCurrentPage := nPageOffset;

    // Índice inicial no ring buffer (reverso)
    nStartIdx := nPageOffset * DISPLAY_LINES;

    // Preencher linhas
    FOR i := 0 TO (DISPLAY_LINES - 1) DO

        bOK := pEventLog.GetEvent(
            nReverseIndex := nStartIdx + i,
            stOut => stEvt
        );

        IF bOK THEN
            Display[i].abLineValid := TRUE;

            // Timestamp → string legível
            Display[i].asTimestamp := FC_EpochToString(stEvt.tTimestamp);

            // Código → mensagem
            Display[i].asMessage := FC_EventCodeToString(stEvt.eCode);

            // Severidade (extraída do nibble alto do código)
            Display[i].asSeverity := FC_SeverityToString(stEvt.eCode);

            // Raise/Clear
            IF stEvt.bRaised THEN
                Display[i].asRaised := 'RAISE';
            ELSE
                Display[i].asRaised := 'CLEAR';
            END_IF

            // Parâmetros numéricos formatados
            Display[i].asParam1 := REAL_TO_STRING(stEvt.rParam1);
            Display[i].asParam2 := REAL_TO_STRING(stEvt.rParam2);
			Display[i].asCodeHex := FC_UIntToHex16Sharp(TO_UINT(stEvt.eCode));
        ELSE
            // Linha vazia
            Display[i].abLineValid  := FALSE;
            Display[i].asTimestamp  := '';
            Display[i].asMessage    := '';
            Display[i].asSeverity   := '';
            Display[i].asRaised     := '';
            Display[i].asParam1     := '';
            Display[i].asParam2		:= '';
			Display[i].asCodeHex	:= '';
        END_IF

    END_FOR

END_IF

// ════════════════════════════════════════════════════════════════════
// FB_EventDisplay — Prepara eventos do ring buffer para exibição na IHM
// ════════════════════════════════════════════════════════════════════
// A IHM não navega o ring buffer diretamente. Este FB expõe
// N linhas "flat" prontas para bind em Text Fields.
//
// Suporta paginação: nPageOffset controla qual "página" exibir.
//   Página 0 = eventos mais recentes
//   Página 1 = próximos DISPLAY_LINES eventos, etc.
//
// Chamado sob demanda (quando operador abre a tela de histórico),
// NÃO a cada ciclo.
// ════════════════════════════════════════════════════════════════════
FUNCTION_BLOCK FB_EventDisplay

VAR_INPUT
    pEventLog       : REFERENCE TO FB_EventLog;     // Referência ao ring buffer
    bRefresh        : BOOL;                         // Pulso = atualiza dados
    nPageOffset     : UINT := 0;                    // Página (0 = mais recente)
END_VAR

VAR_OUTPUT
    nTotalEvents    : UINT;                         // Total de eventos no buffer
    nTotalPages     : UINT;                         // Total de páginas disponíveis
    nCurrentPage    : UINT;                         // Página atual (0-based)
END_VAR

VAR CONSTANT
    DISPLAY_LINES   : UINT := 10;                   // Linhas visíveis na tela
END_VAR

VAR
    // ── Dados "flat" para a IHM (cada linha = 1 evento) ──
	(* 
	ST_EventOutput
    asTimestamp      : STRING(20);   // 'DD/MM HH:MM:SS'
    asMessage        : STRING(60);   // Mensagem legível
    asParam1         : STRING(12);   // Valor contexto 1
    asParam2         : STRING(12);   // Valor contexto 2
    asSeverity       : STRING(8);    // 'INFO'/'WARN'/'ALARM'/'CRIT'
    asRaised         : STRING(5);    // 'RAISE' / 'CLEAR'
    abLineValid      : BOOL;         // TRUE = linha tem dados
	asCodeHex        : STRING(8);    // ex: '16#8700'
	*)

    Display     	: ARRAY[0..9] OF ST_EventOutput;
	
    // Auxiliares
    i               : UINT;
    nStartIdx       : UINT;
    stEvt           : ST_EventEntry;
    bOK             : BOOL;
    rTrigRefresh    : R_TRIG;
END_VAR

IF tEpoch = 0 THEN
    FC_EpochToString := '-- sem RTC --';
    RETURN;
END_IF

// Converte epoch UDINT para DT (DATE_AND_TIME)
// DT no CODESYS V3 é segundos desde 01/01/1970 (mesmo que UDINT epoch)
dtLocal := UDINT_TO_DT(tEpoch);

// Extrai componentes usando funções padrão do SysTime / Util
// Nota: a implementação exata depende das libs disponíveis no target.
// Alternativa simples — usar DT_TO_STRING e truncar:
sTemp := DT_TO_STRING(dtLocal);

// DT_TO_STRING retorna formato 'DT#YYYY-MM-DD-HH:MM:SS'
// Extraímos apenas 'DD/MM HH:MM:SS' (14 chars)
FC_EpochToString := MID(sTemp, 2, 12);  // DD
FC_EpochToString := CONCAT(FC_EpochToString, '/');
FC_EpochToString := CONCAT(FC_EpochToString, MID(sTemp, 2, 9)); // MM
FC_EpochToString := CONCAT(FC_EpochToString, ' ');
FC_EpochToString := CONCAT(FC_EpochToString, MID(sTemp, 8, 15)); // HH:MM:SS

// ════════════════════════════════════════════════════════════════════
// FC_EpochToString — Converte UDINT epoch UTC para string legível
// ════════════════════════════════════════════════════════════════════
// Formato: 'DD/MM HH:MM:SS'
// Simplificação: usa SysTimeRtcConvertUtcToLocal + formatação manual
// Se tTimestamp = 0, retorna '-- sem RTC --'
// ════════════════════════════════════════════════════════════════════
FUNCTION FC_EpochToString : STRING(20)
VAR_INPUT
    tEpoch : UDINT;
END_VAR
VAR
    dtLocal     : DT;
    sTemp       : STRING(20);
    nDay        : UINT;
    nMonth      : UINT;
    nHour       : UINT;
    nMin        : UINT;
    nSec        : UINT;
END_VAR

CASE eCode OF
    // =============================================================
    // NONE
    // =============================================================
    E_EventCode.EVT_NONE:
        FC_EventCodeToString := '';

    // =============================================================
    // INFO (0x1xxx)
    // =============================================================
    // Startup (0x11xx)
    E_EventCode.INFO_STARTUP_BEGIN:
        FC_EventCodeToString := 'Startup: inicio';
    E_EventCode.INFO_SERIAL_COM_OK:
        FC_EventCodeToString := 'Startup: comunicacao serial OK';
    E_EventCode.INFO_RTC_OK:
        FC_EventCodeToString := 'Startup: RTC OK';
    E_EventCode.INFO_INVERTER_COUNT:
        FC_EventCodeToString := 'Startup: quantidade de inversores detectada';
    E_EventCode.INFO_INSTALLED_POWER:
        FC_EventCodeToString := 'Startup: potencia instalada OK';
    E_EventCode.INFO_K1_CONFIRMED:
        FC_EventCodeToString := 'Startup: K1 confirmado';
    E_EventCode.INFO_K2_CONFIRMED:
        FC_EventCodeToString := 'Startup: K2 confirmado';
    E_EventCode.INFO_STARTUP_DONE:
        FC_EventCodeToString := 'Startup: concluido';

    // Medição / Operação (0x12xx)
    E_EventCode.INFO_MEAS_READ_OK:
        FC_EventCodeToString := 'Medidor: leitura OK';
    E_EventCode.INFO_MEAS_DATA_VALID:
        FC_EventCodeToString := 'Medidor: dados validos';
    E_EventCode.INFO_MEAS_RECOVERING:
        FC_EventCodeToString := 'Medicao: recuperando (erros reduzindo)';

    // Escrita inversores (0x13xx)
    E_EventCode.INFO_CH1_WRITE_OK:               
	    FC_EventCodeToString := ' Escrita no canal 01 OK';
	E_EventCode.INFO_CH2_WRITE_OK:               
	    FC_EventCodeToString := ' Escrita no canal 01 OK';
		
    // Scheduler (0x15xx)
    E_EventCode.INFO_SPECIAL_DATE_ACTIVE:
        FC_EventCodeToString := 'Scheduler: data especial ativa';
    E_EventCode.INFO_ZERO_GRID_MODE:
        FC_EventCodeToString := 'Scheduler: modo zero grid ativo';

    // Máquina de estados (0x16xx)
    E_EventCode.INFO_CYCLE_COMPLETE:
        FC_EventCodeToString := 'Ciclo: completo';
    E_EventCode.INFO_FAIL_RECOVERY:
        FC_EventCodeToString := 'FAIL: recuperacao automatica';
    E_EventCode.INFO_STATE_CHANGE:
        FC_EventCodeToString := 'Maquina de estados: mudanca de estado';

    // STOP/Reset (0x18xx)
    E_EventCode.INFO_STOP_K2_OPEN_CONFIRMED:
        FC_EventCodeToString := 'STOP: K2 aberto confirmado';
    E_EventCode.INFO_STOP_RESET_APPROVED:
        FC_EventCodeToString := 'STOP: reset aprovado';
    E_EventCode.INFO_STOP_RESET_WAITING:
        FC_EventCodeToString := 'STOP: aguardando reset';

    // =============================================================
    // WARNING (0x2xxx)
    // =============================================================
    // Startup
    E_EventCode.WARN_TC_POWER_NOT_SET:
        FC_EventCodeToString := 'Startup: TC Power nao configurado';
    E_EventCode.WARN_NO_INVERSORES_COM02:
        FC_EventCodeToString := 'Startup: nenhum inversor no COM2';

    // Medição
    E_EventCode.WARN_MEAS_USING_LAST_VALID:
        FC_EventCodeToString := 'Medicao: usando ultimo valor valido';
    E_EventCode.WARN_MEAS_CROSS_CHECK_PA:
        FC_EventCodeToString := 'Medicao: cross-check Pa falhou';
    E_EventCode.WARN_MEAS_CROSS_CHECK_PB:
        FC_EventCodeToString := 'Medicao: cross-check Pb falhou';
    E_EventCode.WARN_MEAS_CROSS_CHECK_PC:
        FC_EventCodeToString := 'Medicao: cross-check Pc falhou';
    E_EventCode.WARN_MEAS_CROSS_CHECK_PT_SUM:
        FC_EventCodeToString := 'Medicao: cross-check Pt != Pa+Pb+Pc';
    E_EventCode.WARN_MEAS_CROSS_CHECK_PF:
        FC_EventCodeToString := 'Medicao: cross-check PF falhou';
    E_EventCode.WARN_MEAS_ERROR_ISOLATED:
        FC_EventCodeToString := 'Medicao: erro isolado (toleravel)';

    // Comunicação inversores
    E_EventCode.WARN_WRITE_INV_ERROR:
        FC_EventCodeToString := 'Inversores: erro de escrita';
    E_EventCode.WARN_WRITE_INV_TIMEOUT:
        FC_EventCodeToString := 'Inversores: timeout de escrita';

    // Controle
    E_EventCode.WARN_P_ALLOC_SATURATED:
        FC_EventCodeToString := 'Controle: alocacao de P saturada';
    E_EventCode.WARN_Q_LIMITED_BY_SMAX:
        FC_EventCodeToString := 'Controle: Q limitado por Smax';
    E_EventCode.WARN_PF_BELOW_TARGET:
        FC_EventCodeToString := 'Controle: PF abaixo do alvo';
    E_EventCode.WARN_PF_NOT_ACHIEVABLE:
        FC_EventCodeToString := 'Controle: PF nao atingivel';
    E_EventCode.WARN_PI_P_SATURATED:
        FC_EventCodeToString := 'Controle: PI de P saturado';
    E_EventCode.WARN_PI_Q_SATURATED:
        FC_EventCodeToString := 'Controle: PI de Q saturado';
    E_EventCode.WARN_PHASE_LIMITED:
        FC_EventCodeToString := 'Controle: limitado por fase';

    // Ciclo / watchdog
    E_EventCode.WARN_SCAN_OVERRUN:
        FC_EventCodeToString := 'Sistema: scan overrun';

    // STOP/reset
    E_EventCode.WARN_STOP_RESET_DENIED:
        FC_EventCodeToString := 'STOP: reset negado';

    // =============================================================
    // ALARM (0x4xxx)
    // =============================================================
    // Medição — Range/Freeze
    E_EventCode.ALARM_MEAS_VOLTAGE_A_RANGE:
        FC_EventCodeToString := 'Medicao: tensao fase A fora de faixa';
    E_EventCode.ALARM_MEAS_VOLTAGE_B_RANGE:
        FC_EventCodeToString := 'Medicao: tensao fase B fora de faixa';
    E_EventCode.ALARM_MEAS_VOLTAGE_C_RANGE:
        FC_EventCodeToString := 'Medicao: tensao fase C fora de faixa';
    E_EventCode.ALARM_MEAS_CURRENT_A_RANGE:
        FC_EventCodeToString := 'Medicao: corrente fase A fora de faixa';
    E_EventCode.ALARM_MEAS_CURRENT_B_RANGE:
        FC_EventCodeToString := 'Medicao: corrente fase B fora de faixa';
    E_EventCode.ALARM_MEAS_CURRENT_C_RANGE:
        FC_EventCodeToString := 'Medicao: corrente fase C fora de faixa';
    E_EventCode.ALARM_MEAS_PT_RANGE:
        FC_EventCodeToString := 'Medicao: Pt fora de faixa';
    E_EventCode.ALARM_MEAS_PA_RANGE:
        FC_EventCodeToString := 'Medicao: Pa fora de faixa';
    E_EventCode.ALARM_MEAS_PB_RANGE:
        FC_EventCodeToString := 'Medicao: Pb fora de faixa';
    E_EventCode.ALARM_MEAS_PC_RANGE:
        FC_EventCodeToString := 'Medicao: Pc fora de faixa';
    E_EventCode.ALARM_MEAS_QT_RANGE:
        FC_EventCodeToString := 'Medicao: Qt fora de faixa';
    E_EventCode.ALARM_MEAS_QA_RANGE:
        FC_EventCodeToString := 'Medicao: Qa fora de faixa';
    E_EventCode.ALARM_MEAS_QB_RANGE:
        FC_EventCodeToString := 'Medicao: Qb fora de faixa';
    E_EventCode.ALARM_MEAS_QC_RANGE:
        FC_EventCodeToString := 'Medicao: Qc fora de faixa';
    E_EventCode.ALARM_MEAS_PFT_RANGE:
        FC_EventCodeToString := 'Medicao: PFt fora de faixa';
    E_EventCode.ALARM_MEAS_PFA_RANGE:
        FC_EventCodeToString := 'Medicao: PFa fora de faixa';
    E_EventCode.ALARM_MEAS_PFB_RANGE:
        FC_EventCodeToString := 'Medicao: PFb fora de faixa';
    E_EventCode.ALARM_MEAS_PFC_RANGE:
        FC_EventCodeToString := 'Medicao: PFc fora de faixa';
    E_EventCode.ALARM_MEAS_FROZEN:
        FC_EventCodeToString := 'Medicao: congelada (frozen)';

    // Comunicação medidor
    E_EventCode.ALARM_MEAS_MODBUS_ERROR:
        FC_EventCodeToString := 'Medidor: erro Modbus';
    E_EventCode.ALARM_MEAS_MODBUS_TIMEOUT:
        FC_EventCodeToString := 'Medidor: timeout';

    // Comunicação inversores (canal degradado)
    E_EventCode.ALARM_CH1_MODBUS_ERRO:
        FC_EventCodeToString := 'Canal COM1 >50% falhas';
    E_EventCode.ALARM_CH2_MODBUS_ERRO:
        FC_EventCodeToString := 'Canal COM2 >50% falhas';
    E_EventCode.ALARM_CH1_MODBUS_TIMEOUT:
        FC_EventCodeToString := 'Canal COM1 TIMEOUT < 3x';
    E_EventCode.ALARM_CH2_MODBUS_TIMEOUT:
        FC_EventCodeToString := 'Canal COM2 TIMEOUT < 3x';

    // =============================================================
    // CRITICAL (0x8xxx)
    // =============================================================
    // Startup
    E_EventCode.CRIT_SERIAL_INIT_FAILED:
        FC_EventCodeToString := 'Startup: falha init serial';
    E_EventCode.CRIT_RTC_FAILED:
        FC_EventCodeToString := 'Startup: falha RTC';
    E_EventCode.CRIT_NO_INSTALLED_POWER:
        FC_EventCodeToString := 'Startup: potencia instalada = 0';
    E_EventCode.CRIT_K1_TIMEOUT:
        FC_EventCodeToString := 'Startup: timeout K1';

    // Medição
    E_EventCode.CRIT_MEAS_PERSISTENT_FAIL:
        FC_EventCodeToString := 'Medicao: falha persistente';
    E_EventCode.CRIT_MEAS_COM_FAIL:
        FC_EventCodeToString := 'Medidor: falha comunicacao';

    // Comunicação inversores
    E_EventCode.CRIT_INV_CHANNEL_FAIL:
        FC_EventCodeToString := 'Inversores: falha canal comunicacao';

    // Controle
    E_EventCode.CRIT_INSTALLED_POWER_ZERO:
        FC_EventCodeToString := 'Controle: potencia instalada zero';

    // Scheduler
    E_EventCode.CRIT_RTC_READ_FAIL:
        FC_EventCodeToString := 'Scheduler: falha leitura RTC';
    E_EventCode.CRIT_SCHEDULE_INDEX_INVALID:
        FC_EventCodeToString := 'Scheduler: indice invalido';

    // Overrun
    E_EventCode.CRIT_SCAN_OVERRUN:
        FC_EventCodeToString := '3× overruns consecutivos → FAIL';

    // Proteções normativas
    E_EventCode.CRIT_HARDLIMIT_15S:
        FC_EventCodeToString := 'Protecao: HardLimit >15s';
    E_EventCode.CRIT_EXPORT_OVER_LPI_30S:
        FC_EventCodeToString := 'Protecao: Exportacao >LPI >30s';
    E_EventCode.CRIT_MEDIDOR_TIMEOUT_IN_FAIL:
        FC_EventCodeToString := 'Protecao: timeout medidor em FAIL';

    // STOP / Trip
    E_EventCode.CRIT_STOP_ENTRY:
        FC_EventCodeToString := 'STOP: entrada em STOP';
    E_EventCode.CRIT_K2_DID_NOT_OPEN:
        FC_EventCodeToString := 'STOP: K2 nao abriu';
    E_EventCode.CRIT_STATE_CORRUPTION:
        FC_EventCodeToString := 'Sistema: corrupcao de estado';

ELSE
    FC_EventCodeToString := 'Evento desconhecido';
END_CASE

nHighNibble := (TO_UINT(eCode) AND 16#F000);

CASE nHighNibble OF
    16#1000: FC_SeverityToString := 'INFO';
    16#2000: FC_SeverityToString := 'WARN';
    16#4000: FC_SeverityToString := 'ALARM';
    16#8000: FC_SeverityToString := 'CRIT';
ELSE
    FC_SeverityToString := '???';
END_CASE

// ════════════════════════════════════════════════════════════════════
// FC_SeverityToString — Extrai severidade do nibble alto de E_EventCode
// ════════════════════════════════════════════════════════════════════
FUNCTION FC_SeverityToString : STRING(8)
VAR_INPUT
    eCode : E_EventCode;
END_VAR
VAR
    nHighNibble : UINT;
END_VAR

n3 := (uValue AND 16#000F);
n2 := (SHR(uValue, 4)  AND 16#000F);
n1 := (SHR(uValue, 8)  AND 16#000F);
n0 := (SHR(uValue, 12) AND 16#000F);

// Monta '16#' + 4 dígitos
sOut := '16#';
sOut := CONCAT(sOut, MID(aHex, n0 + 1, 1));
sOut := CONCAT(sOut, MID(aHex, n1 + 1, 1));
sOut := CONCAT(sOut, MID(aHex, n2 + 1, 1));
sOut := CONCAT(sOut, MID(aHex, n3 + 1, 1));

FC_UIntToHex16Sharp := sOut;

// ════════════════════════════════════════════════════════════════════
// FC_UIntToHex16Sharp — Formata UINT como '16#XXXX' (4 nibbles)
// Ex.: 16#8700 -> '16#8700'
// tentar usar UINT_TO_HEXSTR se o CODESYS aceitar
// ════════════════════════════════════════════════════════════════════
FUNCTION FC_UIntToHex16Sharp : STRING(7)
VAR_INPUT
    uValue : UINT;
END_VAR
VAR
    aHex   : STRING(16) := '0123456789ABCDEF';
    n0, n1, n2, n3 : UINT;
    sOut : STRING(7);
END_VAR

FOR i := 0 TO (GVL_EventLog.MAX_EVENT_ENTRIES - 1) DO
    aBuffer[i].tTimestamp   := 0;
    aBuffer[i].eCode        := E_EventCode.EVT_NONE;
    aBuffer[i].bRaised      := FALSE;
    aBuffer[i].rParam1      := 0.0;
    aBuffer[i].rParam2      := 0.0;
    aBuffer[i].uMachState   := 0;
END_FOR

nHead := 0;
bWrapped := FALSE;
nTotalLogged := 0;
nCount := 0;
bOverflow := FALSE;

// Registra o próprio clear como primeiro evento do buffer limpo
// (para rastreabilidade — saber que houve reset intencional)
LogEvent(
    eCode       := E_EventCode.INFO_STARTUP_BEGIN,  // Reutiliza como "system reset"
    bRaised     := TRUE,
    rParam1     := 0.0,
    rParam2     := 0.0,
    uMachState  := 0
);

// Validação de range
IF nReverseIndex >= nCount THEN
    // Índice fora do range — zera saída e retorna FALSE
    stOut.tTimestamp     := 0;
    stOut.eCode          := E_EventCode.EVT_NONE;
    stOut.bRaised        := FALSE;
    stOut.rParam1        := 0.0;
    stOut.rParam2        := 0.0;
    stOut.uMachState     := 0;
    GetEvent := FALSE;
    RETURN;
END_IF

// Calcula índice real no buffer circular
// nHead aponta para a PRÓXIMA posição de escrita.
// Último escrito = nHead - 1.
// Índice reverso N = nHead - 1 - N (com wrap-around).
nTemp := UINT_TO_INT(nHead) - 1 - UINT_TO_INT(nReverseIndex);
IF nTemp < 0 THEN
    nTemp := nTemp + UINT_TO_INT(GVL_EventLog.MAX_EVENT_ENTRIES);
END_IF
nActualIdx := INT_TO_UINT(nTemp);

stOut := aBuffer[nActualIdx];
GetEvent := TRUE;

// ════════════════════════════════════════════════════════════════════
// METHOD GetEvent — Lê evento por índice reverso (0 = mais recente)
// ════════════════════════════════════════════════════════════════════
// Para HMI: exibe os últimos N eventos em ordem cronológica reversa.
// Para exportação: itera de 0 a nCount-1.
//
// Retorna TRUE se o índice é válido, FALSE se fora do range.
// Quando retorna FALSE, stOut fica zerado (não retorna lixo).
// ════════════════════════════════════════════════════════════════════
METHOD GetEvent : BOOL
VAR_INPUT
    nReverseIndex   : UINT;     // 0 = mais recente, 1 = anterior, ...
END_VAR
VAR_OUTPUT
    stOut           : ST_EventEntry;
END_VAR
VAR
    nActualIdx      : UINT;
    nTemp           : INT;
END_VAR

// ── 1. Obter timestamp ──
// SysTimeRtcGet retorna epoch UTC em segundos.
// Se RTC falhar (result <> 0), registra timestamp = 0.
// O evento AINDA É REGISTRADO — melhor ter evento sem hora
// do que perder evento crítico por falha de RTC.

tNow := SysTimeRtcGet(result);
IF result <> 0 THEN
    tNow := 0;  // Sinaliza "RTC indisponível" — não descarta o evento
END_IF

// ── 2. Escrever no buffer ──
// nHead já é a posição correta (calculada no final do último LogEvent)
aBuffer[nHead].tTimestamp   := tNow;
aBuffer[nHead].eCode        := eCode;
aBuffer[nHead].bRaised      := bRaised;
aBuffer[nHead].rParam1      := rParam1;
aBuffer[nHead].rParam2      := rParam2;
aBuffer[nHead].uMachState   := uMachState;

// ── 3. Atualizar cópia do último evento (para HMI) ──
stLastEvent := aBuffer[nHead];

// ── 4. Avançar ponteiro circular ──
nHead := (nHead + 1) MOD GVL_EventLog.MAX_EVENT_ENTRIES;

// ── 5. Detectar wrap-around ──
IF nHead = 0 THEN
    bWrapped := TRUE;
END_IF

// ── 6. Atualizar contadores ──
nTotalLogged := nTotalLogged + 1;

// nCount = quantas entradas válidas existem
IF bWrapped THEN
    nCount := GVL_EventLog.MAX_EVENT_ENTRIES;
    bOverflow := TRUE;
ELSE
    nCount := nHead;    // Antes do wrap, nHead = número de entradas escritas
    bOverflow := FALSE;
END_IF

// ════════════════════════════════════════════════════════════════════
// METHOD LogEvent — Insere um evento no ring buffer
// ════════════════════════════════════════════════════════════════════
// Complexidade: O(1). Uma escrita de struct + incremento de ponteiro.
// Pode ser chamado de qualquer FB (ErrorManager, MainProgram, etc.)
//
// IMPORTANTE: Não chame mais de ~5 vezes por ciclo de scan (1s).
// Em cascata de falhas, o caller deve agregar — ex.: registrar
// apenas o primeiro erro de range por ciclo, não um por fase.
// ════════════════════════════════════════════════════════════════════
METHOD LogEvent
VAR_INPUT
    eCode           : E_EventCode;      // Código do evento
    bRaised         : BOOL;             // TRUE = raise, FALSE = clear
    rParam1         : REAL := 0.0;      // Contexto #1 (opcional)
    rParam2         : REAL := 0.0;      // Contexto #2 (opcional)
    uMachState      : UINT := 0;        // Estado da máquina (opcional)
END_VAR
VAR
    tNow            : UDINT;
    result          : RTS_IEC_RESULT;
END_VAR
